// FIREBASE STORE
// ─────────────────────────────────────────────
function liveCol(collName, setter, ...constraints) {
  const q = constraints.length
    ? query(collection(db, collName), ...constraints)
    : collection(db, collName);
  return onSnapshot(q, snap =>
    setter(snap.docs.map(d => ({
      id: d.id, ...d.data(),
      date: d.data().createdAt?.toDate?.()?.toISOString() || d.data().date || new Date().toISOString()
    })))
  );
}

async function adjustStockFB(items, sign) {
  for (const it of (items||[])) {
    if (!it.productId || !it.qty) continue;
    const ref  = doc(db, "products", it.productId);
    const snap = await getDoc(ref);
    if (snap.exists()) {
      const cur = snap.data().stockQty || 0;
      await updateDoc(ref, { stockQty: Math.max(0, cur + sign * Number(it.qty)) });
    }
  }
}

function useStore(userId, userName) {
  const [suppliers,    setSuppliers]    = useState([]);
  const [depots,       setDepots]       = useState([]);
  const [products,     setProducts]     = useState([]);
  const [users,        setUsers]        = useState([]);
  const [entries,      setEntries]      = useState([]);
  const [returns,      setReturns]      = useState([]);
  const [inventories,  setInventories]  = useState([]);
  const [invoices,     setInvoices]     = useState([]);
  const [messages,     setMessages]     = useState([]);
  const [activities,   setActivities]   = useState([]);
  const [services,     setServices]     = useState([]);
  const [transfers,    setTransfers]    = useState([]);
  const [consumptions, setConsumptions] = useState([]);
  const [svcReturns,   setSvcReturns]   = useState([]);
  const [receptions,   setReceptions]   = useState([]);
  const [svcStock,     setSvcStock]     = useState({}); // { "serviceId_productId": qty }
  const [stock,        setStock]        = useState({});
  const [loading,      setLoading]      = useState(true);

  useEffect(() => {
    if (!userId) return;

    // Helper avec gestion d'erreur silencieuse
    const safeLiveCol = (collName, setter, ...constraints) => {
      try { return liveCol(collName, setter, ...constraints); }
      catch(e) { console.warn("Listener error:", collName, e); return ()=>{}; }
    };

    const unsubs = [
      safeLiveCol("suppliers",    setSuppliers,   orderBy("name")),
      safeLiveCol("depots",       setDepots,      orderBy("name")),
      safeLiveCol("users",        setUsers,       orderBy("name")),
      safeLiveCol("entries",      setEntries,     orderBy("createdAt","desc")),
      safeLiveCol("returns",      setReturns,     orderBy("createdAt","desc")),
      safeLiveCol("inventories",  setInventories, orderBy("createdAt","desc")),
      safeLiveCol("invoices",     setInvoices,    orderBy("createdAt","desc")),
      safeLiveCol("messages",     setMessages,    orderBy("createdAt","desc")),
      safeLiveCol("activities",   setActivities,  orderBy("createdAt","desc")),
      safeLiveCol("services",     setServices,    orderBy("name")),
      safeLiveCol("transfers",    setTransfers,   orderBy("createdAt","desc")),
      safeLiveCol("consumptions", setConsumptions,orderBy("createdAt","desc")),
      safeLiveCol("svcReturns",   setSvcReturns,  orderBy("createdAt","desc")),
      safeLiveCol("receptions",   setReceptions,  orderBy("createdAt","desc")),
    ];

    // Listener svcStock avec gestion d'erreur
    let unsubSvcStock = ()=>{};
    try {
      unsubSvcStock = onSnapshot(collection(db,"svcStock"), snap=>{
        const map={};
        snap.docs.forEach(d=>{ map[d.id]=d.data().qty||0; });
        setSvcStock(map);
      }, err=>console.warn("svcStock listener error:", err));
    } catch(e) { console.warn("svcStock init error:", e); }

    const unsubProd = onSnapshot(
      query(collection(db,"products"), orderBy("name")),
      snap => {
        const data = snap.docs.map(d => ({ id: d.id, ...d.data() }));
        setProducts(data);
        const s = {};
        data.forEach(p => { s[p.id] = p.stockQty || 0; });
        setStock(s);
        setLoading(false);
      }
    );
    unsubs.push(unsubProd);
    return () => { unsubs.forEach(u => u()); unsubSvcStock(); };
  }, [userId]);

  return {
    suppliers, depots, products, users,
    entries, returns, inventories, invoices, messages, activities,
    services, transfers, consumptions, svcReturns, receptions, svcStock,
    stock, loading,

    addSupplier:    s    => addDoc(collection(db,"suppliers"), { ...s, createdBy:userId, createdByName:userName, createdAt: serverTimestamp() }), // retourne Promise<DocumentReference>
    updateSupplier: (id,s)=> updateDoc(doc(db,"suppliers",id), s),

    addDepot:    d    => addDoc(collection(db,"depots"), { ...d, createdBy:userId, createdByName:userName, createdAt: serverTimestamp() }),
    updateDepot: (id,d)=> updateDoc(doc(db,"depots",id), d),

    addProduct: async p => {
      const ref = await addDoc(collection(db,"products"), {
        ...p, stockQty: 0, createdBy:userId, createdByName:userName, createdAt: serverTimestamp(),
      });
      return ref.id;
    },
    updateProduct: (id,p) => updateDoc(doc(db,"products",id), p),

    addEntry: async e => {
      const ref = await addDoc(collection(db,"entries"), {
        ...e, type:"entry", createdBy:userId, createdByName:userName, createdAt: serverTimestamp(),
      });
      await adjustStockFB(e.items, +1);
      await addDoc(collection(db,"activities"), { action:"create", entity:"entry", entityId:ref.id, details:`Bon d'entrée créé : ${e.reference} (${e.items?.length||0} article(s))`, userId, userName, createdAt:serverTimestamp() });
      return { id: ref.id, ...e, date: new Date().toISOString() };
    },

    addReturn: async r => {
      const ref = await addDoc(collection(db,"returns"), {
        ...r, type:"return", createdBy:userId, createdByName:userName, createdAt: serverTimestamp(),
      });
      await adjustStockFB(r.items, -1);
      await addDoc(collection(db,"activities"), { action:"create", entity:"return", entityId:ref.id, details:`Bon de retour créé : ${r.reference} (${r.items?.length||0} article(s))`, userId, userName, createdAt:serverTimestamp() });
      return { id: ref.id, ...r, date: new Date().toISOString() };
    },

    addInventory: async inv => {
      const ref = await addDoc(collection(db,"inventories"), {
        ...inv, createdBy:userId, createdByName:userName, createdAt: serverTimestamp(),
      });
      await addDoc(collection(db,"activities"), { action:"create", entity:"inventory", entityId:ref.id, details:`Inventaire créé : ${inv.month} — ${inv.totalSold||0} unité(s) vendue(s)`, userId, userName, createdAt:serverTimestamp() });
      return ref;
    },

    addInvoice: async inv => {
      const ref = await addDoc(collection(db,"invoices"), {
        ...inv, status:"en attente", createdBy:userId, createdByName:userName, createdAt: serverTimestamp(),
      });
      await addDoc(collection(db,"activities"), { action:"create", entity:"invoice", entityId:ref.id, details:`Facture créée : ${inv.reference} — ${Number(inv.total||0).toLocaleString("fr-FR")} FCFA`, userId, userName, createdAt:serverTimestamp() });
      return ref;
    },

    addProduct: async p => {
      const ref = await addDoc(collection(db,"products"), {
        ...p, stockQty: 0, createdBy:userId, createdByName:userName, createdAt: serverTimestamp(),
      });
      await addDoc(collection(db,"activities"), { action:"create", entity:"product", entityId:ref.id, details:`Produit créé : ${p.name}`, userId, userName, createdAt:serverTimestamp() });
      return ref.id;
    },
    updateProduct: async (id,p) => {
      // Récupérer l'ancien nom avant modification
      let oldName = id;
      try { const snap = await getDoc(doc(db,"products",id)); oldName = snap.data()?.name||id; } catch(e){}
      await updateDoc(doc(db,"products",id), p);
      const details = oldName !== (p.name||id)
        ? `Produit modifié : "${oldName}" → "${p.name||id}"`
        : `Produit modifié : "${p.name||id}"`;
      await addDoc(collection(db,"activities"), { action:"update", entity:"product", entityId:id, details, oldName, newName:p.name||id, userId, userName, createdAt:serverTimestamp() });
    },

    deleteEntry: async id => {
      await addDoc(collection(db,"activities"), { action:"delete", entity:"entry", entityId:id, details:`Bon d'entrée supprimé : ${id}`, userId, userName, createdAt:serverTimestamp() });
      return deleteDoc(doc(db,"entries",id));
    },
    deleteReturn: async id => {
      await addDoc(collection(db,"activities"), { action:"delete", entity:"return", entityId:id, details:`Bon de retour supprimé : ${id}`, userId, userName, createdAt:serverTimestamp() });
      return deleteDoc(doc(db,"returns",id));
    },
    deleteInventory: async id => {
      await addDoc(collection(db,"activities"), { action:"delete", entity:"inventory", entityId:id, details:`Inventaire supprimé : ${id}`, userId, userName, createdAt:serverTimestamp() });
      return deleteDoc(doc(db,"inventories",id));
    },
    deleteInvoice: async id => {
      await addDoc(collection(db,"activities"), { action:"delete", entity:"invoice", entityId:id, details:`Facture supprimée : ${id}`, userId, userName, createdAt:serverTimestamp() });
      return deleteDoc(doc(db,"invoices",id));
    },
    deleteProduct: async id => {
      let oldName = id;
      try { const snap = await getDoc(doc(db,"products",id)); oldName = snap.data()?.name||id; } catch(e){}
      await addDoc(collection(db,"activities"), { action:"delete", entity:"product", entityId:id, details:`Produit supprimé : "${oldName}"`, oldName, userId, userName, createdAt:serverTimestamp() });
      return deleteDoc(doc(db,"products",id));
    },
    deleteSupplier: async id => {
      await addDoc(collection(db,"activities"), { action:"delete", entity:"supplier", entityId:id, details:`Fournisseur supprimé : ${id}`, userId, userName, createdAt:serverTimestamp() });
      return deleteDoc(doc(db,"suppliers",id));
    },

    markRead: id => updateDoc(doc(db,"messages",id), { read: true }),

    addUser: async u => {
      const password = (u.tempPw && u.tempPw.length >= 6) ? u.tempPw : "PharmaStock2025!";
      try {
        // Utiliser l'instance Auth secondaire pour NE PAS déconnecter l'admin
        const cred = await createUserWithEmailAndPassword(authSecondary, u.email, password);
        const newUid = cred.user.uid;

        // Déconnecter immédiatement l'instance secondaire
        await signOut(authSecondary);

        // Écrire le document Firestore avec l'UID Auth comme clé
        await setDoc(doc(db, "users", newUid), {
          name:         u.name,
          email:        u.email,
          role:         u.role,
          mustChangePw: true,
          createdAt:    serverTimestamp(),
        });

        // Log activité
        await addDoc(collection(db,"activities"), {
          action:"create", entity:"user",
          details:`Utilisateur créé : ${u.name} (${ROLES[u.role]?.label||u.role})`,
          userId, userName, createdAt:serverTimestamp(),
        });

        return { success:true, uid:newUid };
      } catch(e) {
        // Déconnecter l'instance secondaire en cas d'erreur aussi
        try { await signOut(authSecondary); } catch(_){}
        if(e.code === "auth/email-already-in-use")
          throw new Error("Cet email est déjà utilisé.");
        if(e.code === "auth/invalid-email")
          throw new Error("Adresse email invalide.");
        if(e.code === "auth/weak-password")
          throw new Error("Mot de passe trop faible (min. 6 caractères).");
        throw new Error(e.message || "Erreur inconnue");
      }
    },
    updateUser: async (id,u) => {
      let oldData = {};
      try { const snap = await getDoc(doc(db,"users",id)); oldData = snap.data()||{}; } catch(e){}
      await updateDoc(doc(db,"users",id), u);
      // Construire un message de modification détaillé
      const changes = [];
      if(u.name && u.name !== oldData.name) changes.push(`Nom : "${oldData.name||"—"}" → "${u.name}"`);
      if(u.role && u.role !== oldData.role) changes.push(`Rôle : "${ROLES[oldData.role]?.label||oldData.role||"—"}" → "${ROLES[u.role]?.label||u.role}"`);
      if(u.provisionalPw) changes.push("Mot de passe provisoire défini");
      if(u.permissions) changes.push("Permissions modifiées");
      const details = changes.length > 0
        ? `Utilisateur modifié : "${oldData.name||id}" — ${changes.join(", ")}`
        : `Utilisateur modifié : "${oldData.name||id}"`;
      if(changes.length > 0 || u.name || u.role){
        await addDoc(collection(db,"activities"), { action:"update", entity:"user", entityId:id, details, oldName:oldData.name, newName:u.name||oldData.name, oldRole:oldData.role, newRole:u.role||oldData.role, userId, userName, createdAt:serverTimestamp() });
      }
    },
    deleteUser: async id => {
      let oldData = {};
      try { const snap = await getDoc(doc(db,"users",id)); oldData = snap.data()||{}; } catch(e){}
      const oldName = oldData.name||id;
      const oldRole = ROLES[oldData.role]?.label||oldData.role||"—";
      await addDoc(collection(db,"activities"), { action:"delete", entity:"user", entityId:id, details:`Utilisateur supprimé : "${oldName}" (${oldRole})`, oldName, oldRole, userId, userName, createdAt:serverTimestamp() });
      return deleteDoc(doc(db,"users",id));
    },

    deleteMessage:  (id) => deleteDoc(doc(db,"messages",id)),
    deleteDepot:    (id) => deleteDoc(doc(db,"depots",id)),

    updateEntry:    (id,d) => updateDoc(doc(db,"entries",id),d),
    updateReturn:   (id,d) => updateDoc(doc(db,"returns",id),d),
    updateInventory:(id,d) => updateDoc(doc(db,"inventories",id),d),
    updateInvoice:  (id,d) => updateDoc(doc(db,"invoices",id),d),

    setStockForProduct: (pid,qty) => updateDoc(doc(db,"products",pid), { stockQty: qty }),

    // ── Services hospitaliers ──
    addService:    s => addDoc(collection(db,"services"), { ...s, createdBy:userId, createdAt:serverTimestamp() }),
    updateService: (id,s) => updateDoc(doc(db,"services",id), s),
    deleteService: id => deleteDoc(doc(db,"services",id)),

    // ── Transferts Pharmacie → Service ──
    addTransfer: async t => {
      const ref = await addDoc(collection(db,"transfers"), { ...t, transferredBy:userId, transferredByName:userName, status:"done", createdAt:serverTimestamp() });
      // Décrémenter stock pharmacie + incrémenter stock service
      for(const it of (t.items||[])){
        if(!it.productId||!it.qty) continue;
        const curSnap = await getDoc(doc(db,"products",it.productId));
        const curQty = curSnap.data()?.stockQty || 0;
        await updateDoc(doc(db,"products",it.productId), { stockQty: Math.max(0,curQty - Number(it.qty)) });
        // Stock service : clé composite serviceId_productId
        const sKey = t.serviceId+"_"+it.productId;
        await setDoc(doc(db,"svcStock",sKey), { serviceId:t.serviceId, productId:it.productId, qty:(await getDoc(doc(db,"svcStock",sKey))).data()?.qty||0 + Number(it.qty) }, { merge:true });
      }
      await addDoc(collection(db,"activities"), { action:"create", entity:"transfer", entityId:ref.id, details:`Transfert vers ${t.serviceName} : ${t.items?.length||0} produit(s)`, userId, userName, createdAt:serverTimestamp() });
      return ref;
    },

    // ── Consommations Service ──
    addConsumption: async c => {
      const ref = await addDoc(collection(db,"consumptions"), { ...c, consumedBy:userId, consumedByName:userName, createdAt:serverTimestamp() });
      // Décrémenter stock service
      for(const it of (c.items||[])){
        if(!it.productId||!it.qty) continue;
        const sKey = c.serviceId+"_"+it.productId;
        const snap = await getDoc(doc(db,"svcStock",sKey));
        const cur = snap.data()?.qty||0;
        await setDoc(doc(db,"svcStock",sKey), { serviceId:c.serviceId, productId:it.productId, qty:Math.max(0,cur-Number(it.qty)) }, { merge:true });
      }
      await addDoc(collection(db,"activities"), { action:"create", entity:"consumption", entityId:ref.id, details:`Consommation ${c.serviceName} : ${c.items?.length||0} produit(s)${c.patientName?" — Patient: "+c.patientName:""}`, userId, userName, createdAt:serverTimestamp() });
      return ref;
    },

    // ── Retours Service → Pharmacie ──
    addSvcReturn: async r => {
      const ref = await addDoc(collection(db,"svcReturns"), { ...r, returnedBy:userId, returnedByName:userName, createdAt:serverTimestamp() });
      for(const it of (r.items||[])){
        if(!it.productId||!it.qty) continue;
        // Décrémenter stock service
        const sKey = r.serviceId+"_"+it.productId;
        const snap = await getDoc(doc(db,"svcStock",sKey));
        const cur = snap.data()?.qty||0;
        await setDoc(doc(db,"svcStock",sKey), { serviceId:r.serviceId, productId:it.productId, qty:Math.max(0,cur-Number(it.qty)) }, { merge:true });
        // Incrémenter stock pharmacie
        const pSnap = await getDoc(doc(db,"products",it.productId));
        const pQty = pSnap.data()?.stockQty||0;
        await updateDoc(doc(db,"products",it.productId), { stockQty: pQty+Number(it.qty) });
      }
      await addDoc(collection(db,"activities"), { action:"create", entity:"svcReturn", entityId:ref.id, details:`Retour de ${r.serviceName} vers pharmacie : ${r.items?.length||0} produit(s)`, userId, userName, createdAt:serverTimestamp() });
      return ref;
    },

    getSvcStock: (serviceId, productId) => {
      // Retourner depuis le state local (mis à jour par listener)
      return 0; // sera calculé depuis svcStock
    },

    // ── Listener stock service (dans App) ──
    // ── Réceptions Service (Fournisseur → Pharmacie pour traçabilité service) ──
    addReception: async r => {
      const ref = await addDoc(collection(db,"receptions"), {
        ...r, receivedBy:userId, receivedByName:userName,
        status:"reçu", createdAt:serverTimestamp(),
      });
      await addDoc(collection(db,"activities"), {
        action:"create", entity:"reception", entityId:ref.id,
        details:`Réception : ${r.reference} — ${r.supplierName||""} (${r.items?.length||0} produit(s))`,
        userId, userName, createdAt:serverTimestamp(),
      });
      return ref;
    },
    updateReception: (id,data) => updateDoc(doc(db,"receptions",id), data),
    deleteReception: id => deleteDoc(doc(db,"receptions",id)),

    // ── Méthodes manquantes store ──
    deleteTransfer: id => deleteDoc(doc(db,"transfers",id)),
    updateTransfer: (id,data) => updateDoc(doc(db,"transfers",id), data),

    logActivity: (action, details) =>
      addDoc(collection(db,"activities"), {
        action, details, userId, userName, createdAt: serverTimestamp(),
      }),
  };
}
// ─────────────────────────────────────────────
// AI HOOK
// ─────────────────────────────────────────────
// ─── Construit le contexte données complet pour l'IA ───
function buildAIContext(store, currentUser, activeSupplier, page) {
  const isAdmin = currentUser?.role === "admin";
  const accessiblePages = SECTIONS.filter(s => can(currentUser, s.id, "r")).map(s => s.id);
  accessiblePages.push("dashboard");

  const ctx = {
    utilisateur: { nom: currentUser?.name||"—", role: ROLES[currentUser?.role]?.label||currentUser?.role, email: currentUser?.email },
    fournisseurActif: activeSupplier ? { nom: activeSupplier.name, email: activeSupplier.email } : null,
    pageActuelle: page,
    pagesAccessibles: accessiblePages,
    dateAujourdhui: new Date().toLocaleDateString("fr-FR",{weekday:"long",day:"numeric",month:"long",year:"numeric"}),
  };

  if (can(currentUser,"produits","r")) {
    const prods = activeSupplier ? store.products.filter(p=>p.supplierId===activeSupplier.id) : store.products;
    ctx.produits = prods.map(p=>({ nom:p.name, prix:p.price, stockActuel:store.stock[p.id]||0, alerteStock:(store.stock[p.id]||0)<30 }));
    ctx.stockTotal = prods.reduce((s,p)=>s+(store.stock[p.id]||0),0);
    ctx.produitsEnAlerte = prods.filter(p=>(store.stock[p.id]||0)<30).map(p=>p.name);
  }
  if (can(currentUser,"entrees","r")) {
    const ents = activeSupplier ? store.entries.filter(e=>e.supplierId===activeSupplier.id) : store.entries;
    ctx.entrees = { total: ents.length, ceMois: ents.filter(e=>new Date(e.date).getMonth()===new Date().getMonth()).length,
      recentes: ents.slice(0,10).map(e=>({ ref:e.reference, date:e.date?.substring(0,10), depot:e.depotId, articles:(e.items||[]).length, par:e.createdByName })) };
  }
  if (can(currentUser,"retours","r")) {
    const rets = activeSupplier ? store.returns.filter(r=>r.supplierId===activeSupplier.id) : store.returns;
    ctx.retours = { total: rets.length, ceMois: rets.filter(r=>new Date(r.date).getMonth()===new Date().getMonth()).length };
  }
  if (can(currentUser,"inventaire","r") || can(currentUser,"hist-inv","r")) {
    const invs = activeSupplier ? store.inventories.filter(i=>i.supplierId===activeSupplier.id) : store.inventories;
    ctx.inventaires = { total: invs.length,
      derniers: invs.slice(0,5).map(inv=>({ mois:inv.month, date:inv.date?.substring(0,10), totalVendu:inv.totalSold||0, produits:inv.data?.length||0, par:inv.createdByName,
        detail: (inv.data||[]).filter(r=>r.sold>0).map(r=>({ produit:r.product?.name||"—", vendu:r.sold, stockNouv:r.nw })) })) };
  }
  if (can(currentUser,"factures","r") || can(currentUser,"hist-fact","r")) {
    const facts = activeSupplier ? store.invoices.filter(i=>i.supplierId===activeSupplier.id) : store.invoices;
    ctx.factures = { total:facts.length, enAttente:facts.filter(f=>!f.status||f.status==="en attente").length,
      envoyees:facts.filter(f=>f.status==="envoyée").length, payees:facts.filter(f=>f.status==="payée").length,
      montantTotal:facts.reduce((s,f)=>s+(f.total||0),0),
      recentes: facts.slice(0,5).map(f=>({ ref:f.reference, mois:f.month, montant:f.total, statut:f.status, par:f.createdByName })) };
  }
  if (can(currentUser,"messagerie","r")) {
    ctx.messagerie = { total:store.messages.length, nonLus:store.messages.filter(m=>!m.read).length };
  }
  if (can(currentUser,"fournisseurs","r")) {
    ctx.fournisseurs = store.suppliers.map(s=>({ nom:s.name, email:s.email,
      nbProduits:store.products.filter(p=>p.supplierId===s.id).length,
      nbDepots:store.depots.filter(d=>d.supplierId===s.id).length }));
  }
  if (can(currentUser,"depots","r")) {
    ctx.depots = store.depots.map(d=>({ nom:d.name, localisation:d.location,
      fournisseur:store.suppliers.find(s=>s.id===d.supplierId)?.name||"—" }));
  }
  return ctx;
}

function useAI() {
  const [msgs, setMsgs] = useState([{role:"assistant",content:"Bonjour ! Je suis l'assistant IA de CHNCAK PharmaStock. Je connais vos stocks, inventaires, factures et bons en temps réel. Posez-moi n'importe quelle question sur vos données ou demandez-moi d'ouvrir une page !"}]);
  const [loading, setLoading] = useState(false);

  const send = useCallback(async(text, ctx, onNav, fileData=null)=>{
    const userContent = fileData ? "[Document: " + (fileData.fileName||"fichier") + "]\n" + text : text;
    const newMsgs = [...msgs, {role:"user", content:userContent}];
    setMsgs(newMsgs);
    setLoading(true);

    const dataCtx = ctx.fullData ? JSON.stringify(ctx.fullData, null, 1) : "{}";
    const pagesAccess = (ctx.fullData?.pagesAccessibles || []);

    const system = "Tu es l'assistant IA intelligent de CHNCAK PharmaStock (Centre Hospitalier National Cheikh Ahmadoul Khadim).\n\nUTILISATEUR : " + (ctx.fullData?.utilisateur?.nom||"—") + " | Rôle : " + (ctx.fullData?.utilisateur?.role||"—") + "\n\nNAVIGATION : Utilise [NAVIGATE:nom-page] pour ouvrir une page.\nPages accessibles : " + pagesAccess.join(", ") + "\n\nGÉNÉRATION DE FICHIERS :\n- Pour générer un fichier Excel : [EXCEL:nom_fichier.xlsx]\n  Suivi d'un tableau JSON : [DATA:[{...},{...}]]\n- Pour générer un PDF : [PDF:nom_fichier]\n  Suivi du contenu HTML : [PDFCONTENT:<table>...</table>]\n- Pour générer un CSV : [CSV:nom_fichier.csv]\n  Suivi d'un tableau JSON : [DATA:[{...},{...}]]\n\nEXEMPLES :\n- Rapport stock : génère un Excel avec tous les produits et leurs quantités.\n- Factures du mois : génère un PDF ou Excel avec la liste des factures.\n- Produits en alerte : génère un fichier CSV des produits sous le seuil.\n\nDONNÉES EN TEMPS RÉEL :\n" + dataCtx + "\n\nINSTRUCTIONS :\n1. Réponds en français, de façon précise et professionnelle.\n2. Utilise les données ci-dessus pour répondre sur stocks, quantités, dates, historiques, situations.\n3. Pour naviguer vers une page accessible : [NAVIGATE:nom-page].\n4. Si l'utilisateur demande un fichier, génère-le avec les balises appropriées.\n5. Fais des calculs, comparaisons, résumés à partir des données.\n6. Signale proactivement les stocks bas ou anomalies.\\n7. GÉNÉRATION DE FICHIERS : place TOUT le HTML dans [PDFCONTENT:...] et TOUT le JSON dans [DATA:[...]]. Ne répète JAMAIS le HTML ou JSON brut dans ta réponse.\\n8. IMPORTANT - DONNÉES COMPLÈTES : quand on te demande une liste ou un rapport, tu DOIS inclure la TOTALITÉ des éléments sans exception. Ne tronque JAMAIS une liste. Si on demande les 93 produits, génère les 93 lignes. Écris uniquement un message de confirmation court après les balises.";

    try {
      const res = await fetch("/api/chat", {
        method:"POST",
        headers:{"Content-Type":"application/json"},
        body: JSON.stringify({ system, messages:newMsgs.map(m=>({role:m.role,content:m.content})) })
      });
      if (!res.ok) { const err = await res.json().catch(()=>({})); throw new Error(err.error || "Erreur serveur "+res.status); }
      const data = await res.json();
      if (data.error) throw new Error(data.error);
      const aiText = data.reply || "Désolé, je n'ai pas pu répondre.";

      // ── Navigation ──
      const navMatch = aiText.match(/\[NAVIGATE:([^\]]+)\]/);
      if (navMatch && onNav) {
        const tp = navMatch[1].trim();
        if (pagesAccess.includes(tp) || tp === "dashboard") onNav(tp);
      }

      // ── Génération Excel ──
      const excelMatch = aiText.match(/\[EXCEL:([^\]]+)\]/);
      const dataMatch  = aiText.match(/\[DATA:(\[.*?\])\]/s);
      if (excelMatch && dataMatch) {
        try {
          const fileName = excelMatch[1].trim();
          const rows = JSON.parse(dataMatch[1]);
          if (rows.length > 0) {
            const headers = Object.keys(rows[0]);
            const ws = XLSX.utils.aoa_to_sheet([headers, ...rows.map(r => headers.map(h => r[h] ?? ""))]);
            const wb = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(wb, ws, "Données");
            XLSX.writeFile(wb, fileName);
          }
        } catch(e) { console.warn("Erreur génération Excel:", e); }
      }

      // ── Génération CSV ──
      const csvMatch = aiText.match(/\[CSV:([^\]]+)\]/);
      if (csvMatch && dataMatch) {
        try {
          const fileName = csvMatch[1].trim();
          const rows = JSON.parse(dataMatch[1]);
          if (rows.length > 0) {
            const headers = Object.keys(rows[0]);
            const csv = [headers.join(";"), ...rows.map(r => headers.map(h => String(r[h]??"")||"").join(";"))].join("\n");
            const blob = new Blob([csv], { type:"text/csv;charset=utf-8;" });
            const url  = URL.createObjectURL(blob);
            const a    = document.createElement("a"); a.href=url; a.download=fileName; a.click();
            URL.revokeObjectURL(url);
          }
        } catch(e) { console.warn("Erreur génération CSV:", e); }
      }

      // ── Génération PDF ──
      const pdfMatch     = aiText.match(/\[PDF:([^\]]+)\]/);
      const pdfContent   = aiText.match(/\[PDFCONTENT:(.*?)\]/s);
      if (pdfMatch) {
        try {
          const fileName = pdfMatch[1].trim();
          const htmlBody = pdfContent ? pdfContent[1] : "<p>" + aiText.replace(/\[.*?\]/gs,"").trim() + "</p>";
          const win = window.open("","_blank");
          const html = "<!DOCTYPE html><html><head><meta charset=\"utf-8\"><title>" + fileName + "</title>"
            + "<style>body{font-family:Arial,sans-serif;padding:24px;font-size:13px;}"
            + "table{width:100%;border-collapse:collapse;margin-top:12px;}"
            + "th,td{border:1px solid #cbd5e1;padding:6px 10px;text-align:left;}"
            + "th{background:#0f172a;color:white;}"
            + "tr:nth-child(even){background:#f8fafc;}"
            + "h2{color:#0f172a;}</style></head>"
            + "<body><h2>CHNCAK PharmaStock — " + fileName + "</h2>"
            + htmlBody
            + "<p style=\"margin-top:24px;font-size:11px;color:#64748b;\">Généré le " + new Date().toLocaleDateString("fr-FR") + "</p>"
            + "</body></html>";
          win.document.write(html);
          win.document.close();
          win.print();
        } catch(e) { console.warn("Erreur génération PDF:", e); }
      }

      // Nettoyer les balises du message affiché
      let cleanText = aiText
        .replace(/\[NAVIGATE:[^\]]+\]/g,"")
        .replace(/\[EXCEL:[^\]]+\]/g,"✅ Fichier Excel généré et téléchargé.")
        .replace(/\[CSV:[^\]]+\]/g,"✅ Fichier CSV généré et téléchargé.")
        .replace(/\[PDF:[^\]]+\]/g,"✅ Fichier PDF ouvert pour impression/téléchargement.")
        // Supprimer les blocs DATA et PDFCONTENT (avec contenu potentiellement très long)
        .replace(/\[DATA:\[[\s\S]*?\]\]/g,"")
        .replace(/\[PDFCONTENT:[\s\S]*?\]/g,"")
        // Supprimer tout HTML brut
        .replace(/<table[\s\S]*?<\/table>/gi,"")
        .replace(/<[^>]+>/g,"")
        // Supprimer blocs de code
        .replace(/```[\s\S]*?```/g,"")
        // Supprimer tableaux JSON bruts [ {...}, {...} ]
        .replace(/\[\s*\{[\s\S]*?\}\s*\]/g,"")
        // Supprimer lignes qui ressemblent à du JSON ou données brutes
        .replace(/^\s*[\{\}"\[\],:0-9]+.*$/gm,"")
        // Nettoyer les lignes vides multiples
        .replace(/\n{3,}/g,"\n\n")
        .trim();

      // Si après nettoyage il ne reste que du bruit, mettre un message générique
      if(!cleanText || cleanText.length < 5) {
        const fileType = excelMatch?"Excel":csvMatch?"CSV":pdfMatch?"PDF":"fichier";
        cleanText = "✅ " + fileType + " généré avec succès.";
      }

      setMsgs([...newMsgs, {role:"assistant", content:cleanText}]);
    } catch(e) {
      setMsgs([...newMsgs, {role:"assistant", content:"❌ Erreur IA : " + e.message}]);
    } finally { setLoading(false); }
  }, [msgs]);

  return { msgs, loading, send, reset:()=>setMsgs([{role:"assistant",content:"Session réinitialisée. Comment puis-je vous aider ?"}]) };
}


// ─────────────────────────────────────────────
// SCAN — lecture fichier + appel API Claude
// ─────────────────────────────────────────────
async function readFileAsBase64(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = e => resolve(e.target.result.split(",")[1]);
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

// ─── Lecture Excel avec SheetJS ───
async function readExcelFile(file) {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = e => {
      try {
        const wb  = XLSX.read(e.target.result, { type: "array" });
        const ws  = wb.Sheets[wb.SheetNames[0]];
        const raw = XLSX.utils.sheet_to_json(ws, { defval: "" });
        resolve(raw);
      } catch(err) { reject(err); }
    };
    reader.onerror = reject;
    reader.readAsArrayBuffer(file);
  });
}

// ─── Correspondance souple nom produit ───
function matchProduct(nameInFile, products) {
  if (!nameInFile) return null;
  const norm = s => s.toLowerCase().trim()
    .normalize("NFD").replace(/[\u0300-\u036f]/g,"")
    .replace(/[^a-z0-9]/g," ").replace(/\s+/g," ").trim();

  const n = norm(nameInFile);
  const nWords = n.split(" ").filter(w => w.length > 1);

  // 1. Correspondance exacte normalisée
  const exact = products.find(p => norm(p.name) === n);
  if (exact) return exact;

  // 2. Score : compter les mots significatifs communs
  const scored = products.map(p => {
    const pNorm  = norm(p.name);
    const pWords = pNorm.split(" ").filter(w => w.length > 1);
    // Mots de l'entrée trouvés dans le produit
    const commonN = nWords.filter(w => pWords.includes(w)).length;
    // Mots du produit trouvés dans l'entrée
    const commonP = pWords.filter(w => nWords.includes(w)).length;
    // Score = ratio de mots communs sur total mots du produit
    const score = pWords.length > 0
      ? (commonN + commonP) / (nWords.length + pWords.length)
      : 0;
    return { p, score, commonN, commonP, pWords, nWords };
  }).filter(s => s.score > 0);

  if (scored.length === 0) return null;

  // Trier par score décroissant
  scored.sort((a,b) => b.score - a.score);
  const best = scored[0];

  // Seuil strict : au moins 50% des mots du produit doivent matcher
  // ET au moins 2 mots communs si le produit a plus de 2 mots
  const minWords = best.pWords.length > 2 ? 2 : 1;
  if (best.commonP < minWords) return null;
  if (best.score < 0.35) return null;

  // Si deux candidats ont un score proche, vérifier qu'ils ne sont pas ambigus
  if (scored.length > 1) {
    const second = scored[1];
    // Si le 2e candidat a un score très proche du 1er → ambiguïté → ne pas matcher
    if (second.score > 0 && (best.score - second.score) < 0.1) {
      // Départager : le produit dont le nom normalisé contient le plus de mots du fichier
      if (second.commonN > best.commonN) return second.p;
    }
  }

  return best.p;
}

// ─── Scan Excel : lecture réelle des colonnes ───
async function scanExcelForProducts(file) {
  const rows = await readExcelFile(file);
  if (!rows || rows.length === 0) return { success: false, items: [] };
  // Colonnes possibles (insensible à la casse)
  const get = (row, ...keys) => {
    for (const k of Object.keys(row)) {
      if (keys.some(key => k.toLowerCase().includes(key.toLowerCase()))) {
        const v = row[k];
        if (v !== "" && v !== null && v !== undefined) return String(v).trim();
      }
    }
    return "";
  };
  const items = rows
    .map(row => ({
      productName: get(row,"nom","name","produit","désignation","designation","article","libellé","libelle","description"),
      qty:         get(row,"qté","qty","quantité","quantite","stock","nombre"),
      unitPrice:   get(row,"prix","price","pu","tarif","montant","cout","coût"),
      lot:         get(row,"lot","batch","n°lot"),
      expiry:      get(row,"expir","peremption","péremption","dlc","date limite","date d'expir"),
    }))
    .filter(it => it.productName);
  return { success: true, items, rawCount: rows.length };
}

// ─── Scanner un document (image/PDF/Excel) ───
async function scanDocumentWithAI(file, products) {
  const ext = file.name.split(".").pop().toLowerCase();
  const isImage = ["jpg","jpeg","png","gif","webp"].includes(ext);
  const isPDF   = ext === "pdf";
  const isExcel = ["xlsx","xls","csv","ods"].includes(ext);

  // ── Excel : lecture réelle avec SheetJS ──
  if (isExcel) {
    try {
      const { success, items, rawCount } = await scanExcelForProducts(file);
      if (!success || items.length === 0)
        return { success: false, items: [], error: "Aucune ligne détectée dans le fichier Excel." };
      // Enrichir avec les IDs produits connus
      const enriched = items.map(it => {
        const match = matchProduct(it.productName, products);
        return {
          productId:   match?.id   || "",
          productName: match?.name || it.productName,
          qty:         it.qty      || "",
          unitPrice:   it.unitPrice|| (match?.price ? String(match.price) : ""),
          lot:         it.lot      || "",
          expiry:      it.expiry   || "",
          newProduct:  !match,   // true = produit inconnu → à créer
        };
      });
      return {
        success: true, simulated: false,
        reference: "SCAN-" + Math.random().toString(36).substr(2,6).toUpperCase(),
        items: enriched,
        rawCount,
      };
    } catch(e) {
      console.error("Excel read error:", e);
      return { success: false, items: [], error: "Erreur lecture Excel : " + e.message };
    }
  }

  // ── Image ou PDF : envoi à Claude ──
  const productList = products.map((p,i) => `${i+1}. "${p.name}"`).join("\n");
  const instruction = `Tu es un assistant d'extraction de données pharmaceutiques.
Analyse ce document et extrais les informations de bon d'entrée ou d'inventaire.

LISTE EXACTE DES PRODUITS CONNUS (utilise EXACTEMENT ces noms, ne les modifie pas) :
${productList}

RÈGLES STRICTES DE CORRESPONDANCE :
- Pour chaque ligne du document, trouve le produit qui correspond LE MIEUX dans la liste ci-dessus
- La correspondance doit être PRÉCISE : "Perfuseur" → cherche un produit avec "PERFUSEUR" dans son nom, PAS "SODIUM CHLORURE"
- Pour les variantes (ex: Vicryl 2/0, Vicryl 3/0, Vicryl 5/0) : fais attention aux numéros/tailles, ne confonds PAS Vicryl 2/0 ronde avec Vicryl 3/0 ronde
- Si aucun produit ne correspond exactement, utilise le nom tel qu'il apparaît dans le document
- Ne jamais substituer un produit par un autre qui commence par les mêmes lettres si le reste du nom est différent

Réponds UNIQUEMENT avec du JSON valide, sans markdown, sans texte avant ou après.
Format exact:
{"reference":"BON-XXX","fournisseur":"Nom","items":[{"productName":"nom exact du produit de la liste ou tel que dans le document","qty":0,"unitPrice":0,"lot":"...","expiry":"AAAA-MM-JJ"}]}
Extrait TOUTES les lignes du document.`;

  try {
    let content;
    if (isImage) {
      const b64  = await readFileAsBase64(file);
      const mime = file.type?.startsWith("image/") ? file.type : "image/jpeg";
      content = [
        { type:"image",  source:{ type:"base64", media_type:mime, data:b64 } },
        { type:"text",   text: instruction }
      ];
    } else if (isPDF) {
      const b64 = await readFileAsBase64(file);
      content = [
        { type:"document", source:{ type:"base64", media_type:"application/pdf", data:b64 } },
        { type:"text",     text: instruction }
      ];
    } else {
      return { success: false, items: [], error: "Format non supporté : " + ext };
    }

    const res = await fetch("/api/chat", {
      method:"POST",
      headers:{"Content-Type":"application/json"},
      body: JSON.stringify({ messages:[{ role:"user", content }] })
    });

    if (!res.ok) {
      const errData = await res.json().catch(()=>({}));
      return { success:false, items:[], error: errData.error || "Erreur API Claude." };
    }

    const data    = await res.json();
    const rawText = data.reply || "";

    let parsed = null;
    try { parsed = JSON.parse(rawText.trim()); }
    catch {
      const m = rawText.match(/\{[\s\S]*\}/);
      if (m) try { parsed = JSON.parse(m[0]); } catch { parsed = null; }
    }

    if (!parsed?.items?.length)
      return { success:false, items:[], error:"Aucune donnée extraite du document." };

    const enriched = parsed.items.map(it => {
      const match = matchProduct(it.productName, products);
      return {
        productId:   match?.id   || "",
        productName: match?.name || it.productName || "",
        qty:         String(it.qty || ""),
        unitPrice:   String(it.unitPrice || (match?.price ? String(match.price) : "")),
        lot:         it.lot    || "",
        expiry:      it.expiry || "",
        newProduct:  !match,
      };
    });

    return { success:true, simulated:false,
      reference: parsed.reference || "",
      items: enriched };

  } catch(e) {
    console.error("Scan error:", e);
    return { success:false, items:[], error: e.message };
  }
}

