// ─────────────────────────────────────────────
// SERVICES PAGE
// ─────────────────────────────────────────────
function ServicesPage({store,currentUser}){
  const [show,setShow]=useState(false);
  const [editing,setEditing]=useState(null);
  const [form,setForm]=useState({name:"",description:"",responsable:"",alertThreshold:5});
  const [deletingS,setDeletingS]=useState(null);

  const open=(s=null)=>{
    setEditing(s?.id||null);
    setForm(s?{name:s.name,description:s.description||"",responsable:s.responsable||"",alertThreshold:s.alertThreshold||5}:{name:"",description:"",responsable:"",alertThreshold:5});
    setShow(true);
  };
  const save=()=>{
    if(!form.name.trim()) return;
    if(editing) store.updateService(editing,form); else store.addService(form);
    setShow(false);
  };

  // Calculer le stock total par service
  const getSvcTotal=(sId)=>{
    let total=0;
    Object.entries(store.svcStock||{}).forEach(([k,v])=>{ if(k.startsWith(sId+"_")) total+=v; });
    return total;
  };

  return(
    <div style={{padding:0}}>
      <ConfirmDelete open={!!deletingS} onClose={()=>setDeletingS(null)} label={deletingS?.name||""}
        onConfirm={()=>store.deleteService(deletingS.id)}/>
      <Modal open={show} onClose={()=>setShow(false)} title={editing?"✏️ Modifier Service":"🏥 Nouveau Service"}>
        <div style={{marginBottom:10}}><label style={label}>Nom du service</label><input style={input} value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))} placeholder="Ex: Cardiologie"/></div>
        <div style={{marginBottom:10}}><label style={label}>Description</label><input style={input} value={form.description} onChange={e=>setForm(f=>({...f,description:e.target.value}))}/></div>
        <div style={{marginBottom:10}}><label style={label}>Responsable</label><input style={input} value={form.responsable} onChange={e=>setForm(f=>({...f,responsable:e.target.value}))}/></div>
        <div style={{marginBottom:14}}><label style={label}>Seuil d'alerte stock (unités)</label><input style={input} type="number" min="0" value={form.alertThreshold} onChange={e=>setForm(f=>({...f,alertThreshold:Number(e.target.value)||0}))}/></div>
        <button onClick={save} disabled={!form.name.trim()} style={{...btn(),background:"#dc2626",color:"white",width:"100%",padding:11}}>
          {editing?"✏️ Enregistrer":"🏥 Créer le service"}
        </button>
      </Modal>
      <PageHeader pageId="services" title="🏥 Services Hospitaliers" subtitle="Gestion des services et stocks">
        {can(currentUser,"services","w")&&<button onClick={()=>open()} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>+ Nouveau</button>}
      </PageHeader>
      <div style={{padding:16}}>
        {(store.services||[]).length===0&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucun service créé.</div>}
        {(store.services||[]).map(s=>{
          const total=getSvcTotal(s.id);
          const prodCount=Object.keys(store.svcStock||{}).filter(k=>k.startsWith(s.id+"_")&&store.svcStock[k]>0).length;
          const isAlert=total<=s.alertThreshold;
          return(
            <div key={s.id} style={{...card,marginBottom:10,border:isAlert?"2px solid #ef4444":"1.5px solid #f1f5f9"}}>
              <div style={{display:"flex",alignItems:"flex-start",gap:12}}>
                <div style={{width:44,height:44,borderRadius:12,background:"linear-gradient(135deg,#7f1d1d,#dc2626)",display:"flex",alignItems:"center",justifyContent:"center",fontSize:22,flexShrink:0}}>🏥</div>
                <div style={{flex:1}}>
                  <div style={{fontWeight:700,fontSize:15,color:"#1e293b"}}>{s.name}</div>
                  {s.description&&<div style={{fontSize:12,color:"#64748b"}}>{s.description}</div>}
                  {s.responsable&&<div style={{fontSize:11,color:"#94a3b8"}}>👤 {s.responsable}</div>}
                  <div style={{display:"flex",gap:10,marginTop:6,flexWrap:"wrap"}}>
                    <span style={{background:isAlert?"#fee2e2":"#f0fdf4",color:isAlert?"#ef4444":"#059669",padding:"2px 10px",borderRadius:99,fontSize:11,fontWeight:700}}>
                      {isAlert?"⚠️":"✅"} Stock : {total} unités
                    </span>
                    <span style={{background:"#f0f9ff",color:"#0891b2",padding:"2px 10px",borderRadius:99,fontSize:11}}>
                      {prodCount} produit(s)
                    </span>
                  </div>
                </div>
                <div style={{display:"flex",gap:5,flexShrink:0}}>
                  {can(currentUser,"services","w")&&<button onClick={()=>open(s)} style={{...btn(),background:"#f0f9ff",color:"#0891b2",padding:"5px 8px",fontSize:11}}>✏️</button>}
                  {can(currentUser,"services","d")&&<button onClick={()=>setDeletingS(s)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"5px 8px",fontSize:11}}>🗑️</button>}
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// TRANSFERTS PAGE
// ─────────────────────────────────────────────
function TransfertsPage({store,activeSupplier,currentUser}){
  const [show,setShow]=useState(false);
  const [form,setForm]=useState({serviceId:"",items:[],notes:""});
  const [search,setSearch]=useState("");
  const [showResults,setShowResults]=useState(false);
  const [saving,setSaving]=useState(false);
  const [msg,setMsg]=useState("");
  const searchRef=useRef(null);

  const suppProds=activeSupplier?store.products.filter(p=>p.supplierId===activeSupplier.id):store.products;
  const filtered=search.trim()?suppProds.filter(p=>p.name.toLowerCase().includes(search.toLowerCase())):suppProds;
  const selectedSvc=store.services?.find(s=>s.id===form.serviceId);

  const addItem=(prod)=>{
    setForm(f=>{
      const ex=f.items.find(it=>it.productId===prod.id);
      if(ex) return {...f,items:f.items.map(it=>it.productId===prod.id?{...it,qty:String(Number(it.qty)+1)}:it)};
      return {...f,items:[...f.items,{productId:prod.id,productName:prod.name,qty:"1",stockDispo:store.stock[prod.id]||0}]};
    });
    setSearch(""); setShowResults(false);
  };
  const removeItem=i=>setForm(f=>({...f,items:f.items.filter((_,idx)=>idx!==i)}));

  const save=async()=>{
    if(!form.serviceId){setMsg("⚠️ Sélectionnez un service.");return;}
    if(form.items.length===0){setMsg("⚠️ Ajoutez au moins un produit.");return;}
    setSaving(true);
    try{
      await store.addTransfer({...form,supplierId:activeSupplier?.id,serviceName:selectedSvc?.name});
      setMsg("✅ Transfert effectué avec succès !");
      setForm({serviceId:"",items:[],notes:""});
      setShow(false);
      setTimeout(()=>setMsg(""),4000);
    }catch(e){setMsg("❌ "+e.message);}
    setSaving(false);
  };

  const transfers=(store.transfers||[]).filter(t=>!activeSupplier||t.supplierId===activeSupplier?.id);

  return(
    <div style={{padding:0}}>
      <PageHeader pageId="transferts" title="🔄 Transferts" subtitle={"Pharmacie → Services · "+(activeSupplier?.name||"")}>
        {can(currentUser,"transferts","w")&&<button onClick={()=>setShow(true)} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>+ Nouveau</button>}
      </PageHeader>
      <div style={{padding:16}}>
        {msg&&<Alert type={msg.startsWith("✅")?"success":"warn"}>{msg}</Alert>}

        {/* Modal nouveau transfert */}
        {show&&(
          <div style={{...card,marginBottom:14,border:"2px solid #22c55e"}}>
            <div style={{fontWeight:700,fontSize:14,marginBottom:12,color:"#166534"}}>🔄 Nouveau Transfert</div>
            <div style={{marginBottom:10}}>
              <label style={label}>Service destinataire</label>
              <select style={input} value={form.serviceId} onChange={e=>setForm(f=>({...f,serviceId:e.target.value}))}>
                <option value="">— Choisir un service —</option>
                {(store.services||[]).map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
              </select>
            </div>
            {/* Recherche produit */}
            <div style={{position:"relative",marginBottom:10}}>
              <label style={label}>Ajouter un produit</label>
              <input ref={searchRef} style={{...input,paddingLeft:32}} placeholder="Rechercher..." value={search}
                onChange={e=>{setSearch(e.target.value);setShowResults(true);}}
                onFocus={()=>setShowResults(true)} onBlur={()=>setTimeout(()=>setShowResults(false),150)}/>
              <span style={{position:"absolute",left:10,top:32,fontSize:14}}>🔍</span>
              {showResults&&filtered.length>0&&(
                <div style={{position:"absolute",left:0,right:0,top:"100%",background:"white",border:"1px solid #e2e8f0",borderRadius:8,zIndex:10,maxHeight:180,overflowY:"auto",boxShadow:"0 4px 16px rgba(0,0,0,0.1)"}}>
                  {filtered.slice(0,15).map(p=>(
                    <div key={p.id} onMouseDown={()=>addItem(p)}
                      style={{padding:"8px 12px",cursor:"pointer",borderBottom:"1px solid #f1f5f9",fontSize:12}}>
                      <div style={{fontWeight:600}}>{p.name}</div>
                      <div style={{fontSize:11,color:"#64748b"}}>Stock dispo : {store.stock[p.id]||0}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
            {/* Liste produits sélectionnés */}
            {form.items.map((it,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:8,background:"#f0fdf4",borderRadius:8,padding:"8px 10px",marginBottom:6}}>
                <div style={{flex:1,fontSize:12,fontWeight:600}}>{it.productName}</div>
                <div style={{fontSize:11,color:"#64748b"}}>Dispo:{it.stockDispo}</div>
                <input type="number" min="1" max={it.stockDispo} value={it.qty}
                  onChange={e=>setForm(f=>({...f,items:f.items.map((x,j)=>j===i?{...x,qty:e.target.value}:x)}))}
                  style={{width:60,padding:"4px 6px",border:"1px solid #86efac",borderRadius:6,fontSize:12,textAlign:"center"}}/>
                <button onClick={()=>removeItem(i)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"3px 7px",fontSize:11}}>✕</button>
              </div>
            ))}
            <div style={{marginBottom:10}}><label style={label}>Notes</label><textarea style={{...input,height:50,resize:"none"}} value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}/></div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={save} disabled={saving||!form.serviceId||form.items.length===0}
                style={{...btn(),background:"#16a34a",color:"white",flex:1,padding:10}}>
                {saving?"⏳ Envoi...":"✅ Valider le transfert"}
              </button>
              <button onClick={()=>setShow(false)} style={{...btn(),background:"#f1f5f9",color:"#374151",padding:10}}>Annuler</button>
            </div>
          </div>
        )}

        {/* Historique */}
        {transfers.length===0&&!show&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucun transfert.</div>}
        {transfers.map(t=>(
          <div key={t.id} style={{...card,marginBottom:8}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:6}}>
              <div>
                <div style={{fontWeight:700,fontSize:13}}>🔄 → {t.serviceName||"—"}</div>
                <div style={{fontSize:11,color:"#64748b"}}>{t.transferredByName} · {t.createdAt?.seconds?new Date(t.createdAt.seconds*1000).toLocaleString("fr-FR"):"—"}</div>
              </div>
              <span style={{background:"#dcfce7",color:"#166534",fontSize:10,fontWeight:700,borderRadius:99,padding:"2px 8px"}}>✅ Effectué</span>
            </div>
            {(t.items||[]).map((it,i)=>(
              <div key={i} style={{fontSize:11,color:"#64748b",paddingLeft:8}}>• {it.productName} — {it.qty} unité(s)</div>
            ))}
            {t.notes&&<div style={{fontSize:11,color:"#94a3b8",marginTop:4,fontStyle:"italic"}}>{t.notes}</div>}
          </div>
        ))}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// CONSOMMATIONS PAGE
// ─────────────────────────────────────────────
function ConsommationsPage({store,currentUser}){
  const [show,setShow]=useState(false);
  const [form,setForm]=useState({serviceId:"",patientName:"",patientId:"",note:"",items:[]});
  const [search,setSearch]=useState("");
  const [showResults,setShowResults]=useState(false);
  const [saving,setSaving]=useState(false);
  const [msg,setMsg]=useState("");
  const [showScanner,setShowScanner]=useState(false);
  const searchRef=useRef(null);
  const lastQtyRef=useRef(null);

  // Un agent_service voit uniquement son service
  const userServiceId=currentUser?.serviceId||"";
  const isServiceAgent=currentUser?.role==="agent_service"||currentUser?.role==="admin_service";
  const visibleServices=isServiceAgent&&userServiceId
    ?(store.services||[]).filter(s=>s.id===userServiceId)
    :(store.services||[]);

  const svcProds=form.serviceId
    ?Object.keys(store.svcStock||{}).filter(k=>k.startsWith(form.serviceId+"_")&&store.svcStock[k]>0).map(k=>{
        const prodId=k.split("_")[1];
        return {...(store.products.find(p=>p.id===prodId)||{}), svcQty:store.svcStock[k]};
      }).filter(p=>p.id)
    :[];

  const filtered=search.trim()
    ?svcProds.filter(p=>
        p.name?.toLowerCase().includes(search.toLowerCase())||
        [p.barcode1,p.barcode2,p.barcode3].some(b=>b&&b.includes(search))
      )
    :svcProds;

  const addItem=(prod)=>{
    setForm(f=>{
      const ex=f.items.find(it=>it.productId===prod.id);
      if(ex) return {...f,items:f.items.map(it=>it.productId===prod.id?{...it,qty:String(Number(it.qty)+1)}:it)};
      return {...f,items:[...f.items,{productId:prod.id,productName:prod.name,qty:"1",svcQty:prod.svcQty}]};
    });
    setSearch(""); setShowResults(false);
    setTimeout(()=>{lastQtyRef.current?.focus();lastQtyRef.current?.select();},80);
  };

  const save=async()=>{
    if(!form.serviceId){setMsg("⚠️ Sélectionnez un service.");return;}
    if(form.items.length===0){setMsg("⚠️ Ajoutez au moins un produit.");return;}
    setSaving(true);
    try{
      const svc=store.services?.find(s=>s.id===form.serviceId);
      await store.addConsumption({...form,serviceName:svc?.name||""});
      setMsg("✅ Consommation enregistrée !");
      setForm({serviceId:isServiceAgent?userServiceId:"",patientName:"",patientId:"",note:"",items:[]});
      setShow(false);
      setTimeout(()=>setMsg(""),4000);
    }catch(e){setMsg("❌ "+e.message);}
    setSaving(false);
  };

  const consumptions=(store.consumptions||[]).filter(c=>
    !isServiceAgent||!userServiceId||c.serviceId===userServiceId
  );

  return(
    <div style={{padding:0}}>
      <PageHeader pageId="consommations" title="💉 Consommations" subtitle="Traçabilité produits par patient">
        {can(currentUser,"consommations","w")&&<button onClick={()=>{setForm(f=>({...f,serviceId:isServiceAgent?userServiceId:""}));setShow(true);}} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>+ Saisir</button>}
      </PageHeader>
      <div style={{padding:16}}>
        {msg&&<Alert type={msg.startsWith("✅")?"success":"warn"}>{msg}</Alert>}

        {show&&(
          <div style={{...card,marginBottom:14,border:"2px solid #6366f1"}}>
            <div style={{fontWeight:700,fontSize:14,marginBottom:12,color:"#3730a3"}}>💉 Saisie de consommation</div>
            {!isServiceAgent&&(
              <div style={{marginBottom:10}}>
                <label style={label}>Service</label>
                <select style={input} value={form.serviceId} onChange={e=>setForm(f=>({...f,serviceId:e.target.value,items:[]}))}>
                  <option value="">— Choisir —</option>
                  {visibleServices.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>
            )}
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
              <div><label style={label}>Patient (optionnel)</label><input style={input} value={form.patientName} onChange={e=>setForm(f=>({...f,patientName:e.target.value}))} placeholder="Nom du patient"/></div>
              <div><label style={label}>N° Dossier (optionnel)</label><input style={input} value={form.patientId} onChange={e=>setForm(f=>({...f,patientId:e.target.value}))} placeholder="Ex: PAT-001"/></div>
            </div>
            {form.serviceId&&(
              <div style={{position:"relative",marginBottom:10}}>
                <label style={label}>Produit consommé</label>
                <div style={{display:"flex",gap:6}}>
                  <div style={{position:"relative",flex:1}}>
                    <input ref={searchRef} style={{...input,paddingLeft:32}} placeholder="Nom, code barre ou scanner..."
                      value={search} onChange={e=>{setSearch(e.target.value);setShowResults(true);}}
                      onFocus={()=>setShowResults(true)} onBlur={()=>setTimeout(()=>setShowResults(false),150)}/>
                    <span style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",fontSize:14,pointerEvents:"none"}}>🔍</span>
                  </div>
                  <button onClick={()=>setShowScanner(true)}
                    title="Scanner un code barre"
                    style={{...btn(),background:"#4f46e5",color:"white",padding:"8px 12px",flexShrink:0,fontSize:16}}>
                    📷
                  </button>
                </div>
                {showScanner&&(
                  <BarcodeScanner
                    onDetected={code=>{
                      setShowScanner(false);
                      const found=svcProds.find(p=>
                        [p.barcode1,p.barcode2,p.barcode3].some(b=>b&&b===code)||
                        p.name?.toLowerCase().includes(code.toLowerCase())
                      );
                      if(found) addItem(found);
                      else { setSearch(code); setShowResults(true); }
                    }}
                    onClose={()=>setShowScanner(false)}
                  />
                )}
                {showResults&&filtered.length>0&&(
                  <div style={{position:"absolute",left:0,right:0,top:"100%",background:"white",border:"1px solid #e2e8f0",borderRadius:8,zIndex:10,maxHeight:180,overflowY:"auto",boxShadow:"0 4px 16px rgba(0,0,0,0.1)"}}>
                    {filtered.map(p=>(
                      <div key={p.id} onMouseDown={()=>addItem(p)}
                        style={{padding:"8px 12px",cursor:"pointer",borderBottom:"1px solid #f1f5f9",fontSize:12}}>
                        <div style={{fontWeight:600}}>{p.name}</div>
                        <div style={{fontSize:11,color:"#059669",fontWeight:700}}>Stock service : {p.svcQty}</div>
                      </div>
                    ))}
                  </div>
                )}
                {showResults&&search.trim()&&filtered.length===0&&(
                  <div style={{background:"#fef3c7",borderRadius:8,padding:"8px 12px",fontSize:12,color:"#92400e",marginTop:4}}>
                    ⚠️ Aucun produit trouvé pour « {search} » dans le stock du service.
                  </div>
                )}
              </div>
            )}
            {form.items.map((it,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:8,background:"#eef2ff",borderRadius:8,padding:"8px 10px",marginBottom:6}}>
                <div style={{flex:1,fontSize:12,fontWeight:600}}>{it.productName}</div>
                <div style={{fontSize:11,color:"#6366f1"}}>Stock:{it.svcQty}</div>
                <input ref={i===form.items.length-1?lastQtyRef:null}
                  type="number" min="1" max={it.svcQty} value={it.qty}
                  onChange={e=>setForm(f=>({...f,items:f.items.map((x,j)=>j===i?{...x,qty:e.target.value}:x)}))}
                  style={{width:60,padding:"4px 6px",border:"1px solid #a5b4fc",borderRadius:6,fontSize:12,textAlign:"center"}}/>
                <button onClick={()=>setForm(f=>({...f,items:f.items.filter((_,j)=>j!==i)}))}
                  style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"3px 7px",fontSize:11}}>✕</button>
              </div>
            ))}
            <div style={{marginBottom:10}}><label style={label}>Note</label><textarea style={{...input,height:50,resize:"none"}} value={form.note} onChange={e=>setForm(f=>({...f,note:e.target.value}))}/></div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={save} disabled={saving}
                style={{...btn(),background:"#4f46e5",color:"white",flex:1,padding:10}}>
                {saving?"⏳ Enregistrement...":"✅ Enregistrer"}
              </button>
              <button onClick={()=>setShow(false)} style={{...btn(),background:"#f1f5f9",color:"#374151",padding:10}}>Annuler</button>
            </div>
          </div>
        )}

        {consumptions.length===0&&!show&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucune consommation enregistrée.</div>}
        {consumptions.map(c=>(
          <div key={c.id} style={{...card,marginBottom:8}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:4}}>
              <div>
                <div style={{fontWeight:700,fontSize:13}}>💉 {c.serviceName||"—"}</div>
                {c.patientName&&<div style={{fontSize:12,color:"#4f46e5",fontWeight:600}}>👤 {c.patientName}{c.patientId?" · "+c.patientId:""}</div>}
                <div style={{fontSize:11,color:"#64748b"}}>{c.consumedByName} · {c.createdAt?.seconds?new Date(c.createdAt.seconds*1000).toLocaleString("fr-FR"):"—"}</div>
              </div>
              <span style={{background:"#eef2ff",color:"#4f46e5",fontSize:10,fontWeight:700,borderRadius:99,padding:"2px 8px"}}>{(c.items||[]).length} produit(s)</span>
            </div>
            {(c.items||[]).map((it,i)=>(
              <div key={i} style={{fontSize:11,color:"#64748b",paddingLeft:8}}>• {it.productName} — {it.qty} unité(s)</div>
            ))}
            {c.note&&<div style={{fontSize:11,color:"#94a3b8",marginTop:4,fontStyle:"italic"}}>{c.note}</div>}
          </div>
        ))}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// RETOURS SERVICE PAGE
// ─────────────────────────────────────────────
function RetoursServicePage({store,currentUser}){
  const [show,setShow]=useState(false);
  const [form,setForm]=useState({serviceId:"",items:[],notes:""});
  const [search,setSearch]=useState("");
  const [showResults,setShowResults]=useState(false);
  const [saving,setSaving]=useState(false);
  const [msg,setMsg]=useState("");

  const userServiceId=currentUser?.serviceId||"";
  const isServiceAgent=currentUser?.role==="agent_service"||currentUser?.role==="admin_service";

  const svcProds=form.serviceId
    ?Object.keys(store.svcStock||{}).filter(k=>k.startsWith(form.serviceId+"_")&&store.svcStock[k]>0).map(k=>{
        const prodId=k.split("_")[1];
        return {...(store.products.find(p=>p.id===prodId)||{}),svcQty:store.svcStock[k]};
      }).filter(p=>p.id)
    :[];
  const filtered=search.trim()?svcProds.filter(p=>p.name?.toLowerCase().includes(search.toLowerCase())):svcProds;

  const addItem=(prod)=>{
    setForm(f=>{
      const ex=f.items.find(it=>it.productId===prod.id);
      if(ex) return {...f,items:f.items.map(it=>it.productId===prod.id?{...it,qty:String(Number(it.qty)+1)}:it)};
      return {...f,items:[...f.items,{productId:prod.id,productName:prod.name,qty:"1",svcQty:prod.svcQty}]};
    });
    setSearch(""); setShowResults(false);
  };

  const save=async()=>{
    if(!form.serviceId){setMsg("⚠️ Sélectionnez un service.");return;}
    if(form.items.length===0){setMsg("⚠️ Ajoutez au moins un produit.");return;}
    setSaving(true);
    try{
      const svc=store.services?.find(s=>s.id===form.serviceId);
      await store.addSvcReturn({...form,serviceName:svc?.name||""});
      setMsg("✅ Retour enregistré — stock pharmacie mis à jour !");
      setForm({serviceId:isServiceAgent?userServiceId:"",items:[],notes:""});
      setShow(false);
      setTimeout(()=>setMsg(""),4000);
    }catch(e){setMsg("❌ "+e.message);}
    setSaving(false);
  };

  const returns=(store.svcReturns||[]).filter(r=>!isServiceAgent||!userServiceId||r.serviceId===userServiceId);

  return(
    <div style={{padding:0}}>
      <PageHeader pageId="retours-service" title="↩️ Retours Service" subtitle="Service → Pharmacie">
        {can(currentUser,"retours-service","w")&&<button onClick={()=>setShow(true)} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>+ Nouveau retour</button>}
      </PageHeader>
      <div style={{padding:16}}>
        {msg&&<Alert type={msg.startsWith("✅")?"success":"warn"}>{msg}</Alert>}
        {show&&(
          <div style={{...card,marginBottom:14,border:"2px solid #d97706"}}>
            <div style={{fontWeight:700,fontSize:14,marginBottom:12,color:"#92400e"}}>↩️ Retour vers la pharmacie</div>
            {!isServiceAgent&&(
              <div style={{marginBottom:10}}>
                <label style={label}>Service</label>
                <select style={input} value={form.serviceId} onChange={e=>setForm(f=>({...f,serviceId:e.target.value,items:[]}))}>
                  <option value="">— Choisir —</option>
                  {(store.services||[]).map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
                </select>
              </div>
            )}
            {form.serviceId&&(
              <div style={{position:"relative",marginBottom:10}}>
                <label style={label}>Produit à retourner</label>
                <input style={{...input,paddingLeft:32}} placeholder="Rechercher dans stock service..."
                  value={search} onChange={e=>{setSearch(e.target.value);setShowResults(true);}}
                  onFocus={()=>setShowResults(true)} onBlur={()=>setTimeout(()=>setShowResults(false),150)}/>
                <span style={{position:"absolute",left:10,top:32,fontSize:14}}>🔍</span>
                {showResults&&filtered.length>0&&(
                  <div style={{position:"absolute",left:0,right:0,top:"100%",background:"white",border:"1px solid #e2e8f0",borderRadius:8,zIndex:10,maxHeight:160,overflowY:"auto",boxShadow:"0 4px 16px rgba(0,0,0,0.1)"}}>
                    {filtered.map(p=>(
                      <div key={p.id} onMouseDown={()=>addItem(p)} style={{padding:"8px 12px",cursor:"pointer",borderBottom:"1px solid #f1f5f9",fontSize:12}}>
                        <div style={{fontWeight:600}}>{p.name}</div>
                        <div style={{fontSize:11,color:"#d97706",fontWeight:700}}>Stock service : {p.svcQty}</div>
                      </div>
                    ))}
                  </div>
                )}
              </div>
            )}
            {form.items.map((it,i)=>(
              <div key={i} style={{display:"flex",alignItems:"center",gap:8,background:"#fffbeb",borderRadius:8,padding:"8px 10px",marginBottom:6}}>
                <div style={{flex:1,fontSize:12,fontWeight:600}}>{it.productName}</div>
                <div style={{fontSize:11,color:"#d97706"}}>Stock:{it.svcQty}</div>
                <input type="number" min="1" max={it.svcQty} value={it.qty}
                  onChange={e=>setForm(f=>({...f,items:f.items.map((x,j)=>j===i?{...x,qty:e.target.value}:x)}))}
                  style={{width:60,padding:"4px 6px",border:"1px solid #fcd34d",borderRadius:6,fontSize:12,textAlign:"center"}}/>
                <button onClick={()=>setForm(f=>({...f,items:f.items.filter((_,j)=>j!==i)}))}
                  style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"3px 7px",fontSize:11}}>✕</button>
              </div>
            ))}
            <div style={{marginBottom:10}}><label style={label}>Notes</label><textarea style={{...input,height:50,resize:"none"}} value={form.notes} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}/></div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={save} disabled={saving}
                style={{...btn(),background:"#d97706",color:"white",flex:1,padding:10}}>
                {saving?"⏳ Traitement...":"✅ Valider le retour"}
              </button>
              <button onClick={()=>setShow(false)} style={{...btn(),background:"#f1f5f9",color:"#374151",padding:10}}>Annuler</button>
            </div>
          </div>
        )}
        {returns.length===0&&!show&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucun retour enregistré.</div>}
        {returns.map(r=>(
          <div key={r.id} style={{...card,marginBottom:8}}>
            <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:4}}>
              <div>
                <div style={{fontWeight:700,fontSize:13}}>↩️ {r.serviceName||"—"} → Pharmacie</div>
                <div style={{fontSize:11,color:"#64748b"}}>{r.returnedByName} · {r.createdAt?.seconds?new Date(r.createdAt.seconds*1000).toLocaleString("fr-FR"):"—"}</div>
              </div>
            </div>
            {(r.items||[]).map((it,i)=>(
              <div key={i} style={{fontSize:11,color:"#64748b",paddingLeft:8}}>• {it.productName} — {it.qty} unité(s)</div>
            ))}
            {r.notes&&<div style={{fontSize:11,color:"#94a3b8",marginTop:4,fontStyle:"italic"}}>{r.notes}</div>}
          </div>
        ))}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// RECEPTIONS PAGE (Fournisseur → Pharmacie pour traçabilité service)
// ─────────────────────────────────────────────
function ReceptionsPage({store,activeSupplier,currentUser}){
  const [show,setShow]=useState(false);
  const [selected,setSelected]=useState(null);
  const [editing,setEditing]=useState(null);
  const [form,setForm]=useState({reference:"",supplierId:"",supplierName:"",date:new Date().toISOString().split("T")[0],items:[],notes:""});
  const [search,setSearch]=useState("");
  const [showResults,setShowResults]=useState(false);
  const [saving,setSaving]=useState(false);
  const [msg,setMsg]=useState("");
  const [showScanner,setShowScanner]=useState(false);
  const searchRef=useRef(null);
  const lastQtyRef=useRef(null);

  const suppProds=activeSupplier?store.products.filter(p=>p.supplierId===activeSupplier.id):store.products;
  const filtered=search.trim()
    ?suppProds.filter(p=>p.name.toLowerCase().includes(search.toLowerCase())||[p.barcode1,p.barcode2,p.barcode3].some(b=>b&&b.includes(search)))
    :suppProds;
  const receptions=(store.receptions||[]).filter(r=>!activeSupplier||r.supplierId===activeSupplier.id);

  const openNew=()=>{
    setEditing(null);
    setForm({reference:"BON-REC-"+genId(),supplierId:activeSupplier?.id||"",supplierName:activeSupplier?.name||"",date:new Date().toISOString().split("T")[0],items:[],notes:""});
    setShow(true); setSelected(null);
  };

  const addItem=(prod)=>{
    setForm(f=>{
      const ex=f.items.find(i=>i.productId===prod.id);
      if(ex) return {...f,items:f.items.map(i=>i.productId===prod.id?{...i,qty:String(Number(i.qty)+1)}:i)};
      return {...f,items:[...f.items,{productId:prod.id,productName:prod.name,qty:"1",unitPrice:String(prod.price||""),lot:"",expiry:""}]};
    });
    setSearch(""); setShowResults(false);
    setTimeout(()=>{lastQtyRef.current?.focus();lastQtyRef.current?.select();},80);
  };

  const save=async()=>{
    if(!form.items.length){setMsg("⚠️ Ajoutez au moins un produit.");return;}
    setSaving(true);
    try{
      if(editing){
        await store.updateReception(editing,{...form});
        setMsg("✅ Réception modifiée !");
      } else {
        await store.addReception({...form});
        setMsg("✅ Réception enregistrée !");
      }
      setShow(false); setEditing(null);
      setTimeout(()=>setMsg(""),4000);
    }catch(e){setMsg("❌ "+e.message);}
    setSaving(false);
  };

  const printReception=(r)=>{
    const rows=(r.items||[]).map((it,i)=>
      "<tr style=\"background:"+(i%2===0?"#fff":"#f8fafc")+"\">" +
      "<td>"+it.productName+"</td><td style=\"text-align:center\">"+it.qty+"</td>" +
      "<td style=\"text-align:right\">"+Number(it.unitPrice||0).toLocaleString("fr-FR")+"</td>" +
      "<td style=\"text-align:right;font-weight:600\">"+Number((it.qty||0)*(it.unitPrice||0)).toLocaleString("fr-FR")+"</td></tr>"
    ).join("");
    const total=r.items?.reduce((s,i)=>s+Number(i.qty||0)*Number(i.unitPrice||0),0)||0;
    const html=
      "<!DOCTYPE html><html><head><meta charset=\"utf-8\"><title>Réception "+r.reference+"</title>"+
      "<style>@page{size:A4;margin:1.5cm}*{box-sizing:border-box;margin:0;padding:0}body{font-family:Arial,sans-serif;font-size:10px}"+
      ".hd{background:#065f46;color:#fff;padding:10px;font-size:13px;font-weight:bold;text-align:center;margin-bottom:4px}"+
      ".sub{background:#047857;color:#fff;padding:4px;font-size:10px;text-align:center;margin-bottom:8px}"+
      ".info{display:flex;justify-content:space-between;font-size:9px;color:#444;margin-bottom:8px}"+
      "table{width:100%;border-collapse:collapse;font-size:10px}"+
      "th{background:#065f46;color:#fff;padding:6px 8px;text-align:center;border:1px solid #064e3b}"+
      "td{padding:5px 8px;border:1px solid #ddd}"+
      ".tot{background:#065f46;color:#fff;font-weight:bold}"+
      ".sig{display:grid;grid-template-columns:1fr 1fr;gap:20px;margin-top:30px}"+
      ".sb{text-align:center}.sl{font-weight:bold;font-size:9px;color:#065f46;margin-bottom:50px}"+
      ".su{border-top:1.5px solid #333;margin-top:2px}</style></head><body>"+
      "<div class=\"hd\">CENTRE HOSPITALIER NATIONAL CHEIKH AHMADOUL KHADIM</div>"+
      "<div class=\"sub\">BON DE RÉCEPTION — PHARMACIE CHNCAK</div>"+
      "<div class=\"info\"><span>Réf : <strong>"+r.reference+"</strong></span><span>Fournisseur : <strong>"+r.supplierName+"</strong></span><span>Date : "+r.date+"</span></div>"+
      "<table><thead><tr><th style=\"width:45%\">DÉSIGNATION</th><th>QTÉ</th><th>PRIX UNIT. (FCFA)</th><th>TOTAL (FCFA)</th></tr></thead><tbody>"+
      rows+"<tr class=\"tot\"><td colspan=\"3\" style=\"text-align:center\">TOTAL</td><td style=\"text-align:right\">"+total.toLocaleString("fr-FR")+"</td></tr></tbody></table>"+
      (r.notes?"<div style=\"margin-top:8px;font-size:9px;color:#444;font-style:italic\">Notes : "+r.notes+"</div>":"")+
      "<div class=\"sig\"><div class=\"sb\"><div class=\"sl\">Le Fournisseur</div><div class=\"su\"></div></div>"+
      "<div class=\"sb\"><div class=\"sl\">Le Chef de service Pharmacie CHNCAK</div><div class=\"su\"></div></div></div>"+
      "</body></html>";
    const blob=new Blob([html],{type:"text/html;charset=utf-8"});
    const url=URL.createObjectURL(blob);
    const win=window.open(url,"_blank");
    if(win) win.addEventListener("load",()=>{setTimeout(()=>{win.print();URL.revokeObjectURL(url);},400);});
  };

  // Vue détail
  if(selected){
    const r=selected;
    const total=r.items?.reduce((s,i)=>s+Number(i.qty||0)*Number(i.unitPrice||0),0)||0;
    return(
      <div style={{padding:0}}>
        <PageHeader pageId="receptions" title="📦 Bon de Réception" subtitle={r.reference}>
          <button onClick={()=>setSelected(null)} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>← Retour</button>
        </PageHeader>
        <div style={{padding:16}}>
          <div style={{background:"#065f46",color:"white",borderRadius:"8px 8px 0 0",padding:"10px 14px",fontWeight:800,fontSize:13}}>
            BON DE RÉCEPTION — PHARMACIE CHNCAK
          </div>
          <div style={{background:"#f0fdf4",border:"1px solid #bbf7d0",borderRadius:"0 0 8px 8px",padding:"10px 14px",marginBottom:12}}>
            <div style={{display:"flex",justifyContent:"space-between",flexWrap:"wrap",gap:8,fontSize:12}}>
              <div><b>Réf :</b> {r.reference}</div>
              <div><b>Fournisseur :</b> {r.supplierName}</div>
              <div><b>Date :</b> {r.date}</div>
              <div><b>Par :</b> {r.receivedByName}</div>
            </div>
          </div>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:11,marginBottom:8}}>
            <thead><tr>
              {["DÉSIGNATION","QTÉ","PRIX UNIT.","TOTAL"].map(h=><th key={h} style={{background:"#065f46",color:"white",padding:"6px 8px",border:"1px solid #064e3b",textAlign:"center"}}>{h}</th>)}
            </tr></thead>
            <tbody>
              {(r.items||[]).map((it,i)=>(
                <tr key={i} style={{background:i%2===0?"white":"#f0fdf4"}}>
                  <td style={{padding:"5px 8px",border:"1px solid #ddd"}}>{it.productName}</td>
                  <td style={{padding:"5px 8px",border:"1px solid #ddd",textAlign:"center"}}>{it.qty}</td>
                  <td style={{padding:"5px 8px",border:"1px solid #ddd",textAlign:"right"}}>{Number(it.unitPrice||0).toLocaleString("fr-FR")}</td>
                  <td style={{padding:"5px 8px",border:"1px solid #ddd",textAlign:"right",fontWeight:700}}>{(Number(it.qty||0)*Number(it.unitPrice||0)).toLocaleString("fr-FR")}</td>
                </tr>
              ))}
              <tr style={{background:"#065f46",color:"white"}}>
                <td colSpan={3} style={{padding:"6px 8px",border:"1px solid #064e3b",textAlign:"center",fontWeight:800}}>TOTAL</td>
                <td style={{padding:"6px 8px",border:"1px solid #064e3b",textAlign:"right",fontWeight:800,fontSize:13}}>{total.toLocaleString("fr-FR")} FCFA</td>
              </tr>
            </tbody>
          </table>
          {r.notes&&<div style={{fontSize:11,color:"#64748b",fontStyle:"italic",marginBottom:12}}>Notes : {r.notes}</div>}
          <div style={{display:"flex",gap:8,flexWrap:"wrap"}}>
            {can(currentUser,"receptions","w")&&<button onClick={()=>{setEditing(r.id);setForm({...r});setShow(true);setSelected(null);}} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #86efac",fontSize:12}}>✏️ Modifier</button>}
            <button onClick={()=>printReception(r)} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>🖨️ Imprimer</button>
            {can(currentUser,"receptions","d")&&<button onClick={()=>{if(window.confirm("Supprimer ce bon de réception ?")){store.deleteReception(r.id);setSelected(null);}}} style={{...btn(),background:"#fee2e2",color:"#ef4444",border:"1px solid #fca5a5",fontSize:12}}>🗑️ Supprimer</button>}
          </div>
        </div>
      </div>
    );
  }

  return(
    <div style={{padding:0}}>
      <PageHeader pageId="receptions" title="📦 Réceptions Service" subtitle={activeSupplier?.name||"Tous fournisseurs"}>
        {can(currentUser,"receptions","w")&&<button onClick={openNew} style={{...btn(),background:"rgba(255,255,255,0.15)",color:"white",border:"1px solid rgba(255,255,255,0.3)",fontSize:12}}>+ Nouveau bon</button>}
      </PageHeader>
      <div style={{padding:16}}>
        {msg&&<Alert type={msg.startsWith("✅")?"success":"warn"}>{msg}</Alert>}

        {/* Formulaire */}
        {show&&(
          <div style={{...card,marginBottom:14,border:"2px solid #059669"}}>
            <div style={{fontWeight:700,fontSize:14,marginBottom:12,color:"#065f46"}}>📦 {editing?"Modifier":"Nouveau"} Bon de Réception</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
              <div><label style={label}>Référence</label><input style={input} value={form.reference} onChange={e=>setForm(f=>({...f,reference:e.target.value}))}/></div>
              <div><label style={label}>Date</label><input style={{...input}} type="date" value={form.date} onChange={e=>setForm(f=>({...f,date:e.target.value}))}/></div>
            </div>
            <div style={{marginBottom:10}}>
              <label style={label}>Fournisseur</label>
              {activeSupplier?<div style={{...input,background:"#f0fdf4",color:"#065f46",fontWeight:600}}>🏢 {activeSupplier.name}</div>:
              <select style={input} value={form.supplierId} onChange={e=>{const s=store.suppliers.find(x=>x.id===e.target.value);setForm(f=>({...f,supplierId:e.target.value,supplierName:s?.name||""}));}}>
                <option value="">— Choisir —</option>
                {store.suppliers.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
              </select>}
            </div>
            {/* Recherche produit */}
            <div style={{position:"relative",marginBottom:10}}>
              <label style={label}>Ajouter un produit</label>
              <div style={{display:"flex",gap:6}}>
                <div style={{position:"relative",flex:1}}>
                  <input ref={searchRef} style={{...input,paddingLeft:32}} placeholder="Nom ou code barre..."
                    value={search} onChange={e=>{setSearch(e.target.value);setShowResults(true);}}
                    onFocus={()=>setShowResults(true)} onBlur={()=>setTimeout(()=>setShowResults(false),150)}/>
                  <span style={{position:"absolute",left:10,top:"50%",transform:"translateY(-50%)",fontSize:14,pointerEvents:"none"}}>🔍</span>
                </div>
                <button onClick={()=>setShowScanner(true)} style={{...btn(),background:"#0891b2",color:"white",padding:"8px 12px",flexShrink:0}}>📷</button>
              </div>
              {showResults&&filtered.length>0&&(
                <div style={{position:"absolute",left:0,right:0,top:"100%",background:"white",border:"1px solid #e2e8f0",borderRadius:8,zIndex:10,maxHeight:180,overflowY:"auto",boxShadow:"0 4px 16px rgba(0,0,0,0.1)"}}>
                  {filtered.slice(0,15).map(p=>(
                    <div key={p.id} onMouseDown={()=>addItem(p)} style={{padding:"8px 12px",cursor:"pointer",borderBottom:"1px solid #f1f5f9",fontSize:12}}>
                      <div style={{fontWeight:600}}>{p.name}</div>
                      <div style={{fontSize:11,color:"#64748b"}}>{Number(p.price||0).toLocaleString("fr-FR")} FCFA · {p.unit||"Boîte"}</div>
                    </div>
                  ))}
                </div>
              )}
            </div>
            {showScanner&&<BarcodeScanner onDetected={code=>{setShowScanner(false);const p=suppProds.find(x=>[x.barcode1,x.barcode2,x.barcode3].includes(code)||x.name.toLowerCase().includes(code.toLowerCase()));if(p)addItem(p);else setSearch(code);}} onClose={()=>setShowScanner(false)}/>}
            {/* Liste produits */}
            {form.items.map((it,i)=>(
              <div key={i} style={{background:"#f0fdf4",borderRadius:8,padding:"8px 10px",marginBottom:6,border:"1px solid #86efac"}}>
                <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                  <div style={{fontWeight:600,fontSize:12}}>{it.productName}</div>
                  <button onClick={()=>setForm(f=>({...f,items:f.items.filter((_,j)=>j!==i)}))} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"2px 7px",fontSize:11}}>✕</button>
                </div>
                <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr 1fr",gap:6}}>
                  <div><label style={{...label,fontSize:9}}>Qté</label>
                    <input ref={i===form.items.length-1?lastQtyRef:null} type="number" min="0" value={it.qty}
                      onChange={e=>setForm(f=>({...f,items:f.items.map((x,j)=>j===i?{...x,qty:e.target.value}:x)}))}
                      style={{...input,textAlign:"center"}}/></div>
                  <div><label style={{...label,fontSize:9}}>Prix unit.</label>
                    <input type="number" min="0" value={it.unitPrice}
                      onChange={e=>setForm(f=>({...f,items:f.items.map((x,j)=>j===i?{...x,unitPrice:e.target.value}:x)}))}
                      style={input}/></div>
                  <div><label style={{...label,fontSize:9}}>N° Lot</label>
                    <input value={it.lot||""} onChange={e=>setForm(f=>({...f,items:f.items.map((x,j)=>j===i?{...x,lot:e.target.value}:x)}))} style={input}/></div>
                  <div><label style={{...label,fontSize:9}}>Expiration</label>
                    <input type="date" value={it.expiry||""} onChange={e=>setForm(f=>({...f,items:f.items.map((x,j)=>j===i?{...x,expiry:e.target.value}:x)}))} style={input}/></div>
                </div>
                <div style={{textAlign:"right",fontSize:11,color:"#059669",fontWeight:700,marginTop:4}}>
                  Sous-total : {(Number(it.qty||0)*Number(it.unitPrice||0)).toLocaleString("fr-FR")} FCFA
                </div>
              </div>
            ))}
            <div style={{marginBottom:10}}><label style={label}>Notes</label><textarea style={{...input,height:50,resize:"none"}} value={form.notes||""} onChange={e=>setForm(f=>({...f,notes:e.target.value}))}/></div>
            <div style={{display:"flex",gap:8}}>
              <button onClick={save} disabled={saving||form.items.length===0}
                style={{...btn(),background:form.items.length===0?"#cbd5e1":"#059669",color:"white",flex:1,padding:10}}>
                {saving?"⏳ Enregistrement...":"✅ Valider le bon de réception"}
              </button>
              <button onClick={()=>{setShow(false);setEditing(null);}} style={{...btn(),background:"#f1f5f9",color:"#374151",padding:10}}>Annuler</button>
            </div>
          </div>
        )}

        {/* Liste */}
        {receptions.length===0&&!show&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucun bon de réception.</div>}
        {receptions.map(r=>{
          const total=r.items?.reduce((s,i)=>s+Number(i.qty||0)*Number(i.unitPrice||0),0)||0;
          return(
            <div key={r.id} onClick={()=>setSelected(r)}
              style={{...card,marginBottom:8,cursor:"pointer",transition:"box-shadow 0.15s"}}
              onMouseEnter={e=>e.currentTarget.style.boxShadow="0 4px 16px rgba(0,0,0,0.1)"}
              onMouseLeave={e=>e.currentTarget.style.boxShadow=""}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start"}}>
                <div>
                  <div style={{fontWeight:700,fontSize:13,color:"#065f46"}}>📦 {r.reference}</div>
                  <div style={{fontSize:11,color:"#64748b"}}>{r.supplierName} · {r.date}</div>
                  <div style={{fontSize:11,color:"#94a3b8"}}>{r.items?.length||0} produit(s) · Par {r.receivedByName}</div>
                </div>
                <div style={{textAlign:"right"}}>
                  <div style={{fontWeight:800,color:"#059669",fontSize:15}}>{total.toLocaleString("fr-FR")} FCFA</div>
                  <span style={{background:"#dcfce7",color:"#059669",fontSize:10,fontWeight:700,borderRadius:99,padding:"2px 8px"}}>{r.status||"reçu"}</span>
                </div>
                <div style={{color:"#cbd5e1",fontSize:18,marginLeft:8}}>›</div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// STOCK SERVICE PAGE — Vue multi-fournisseurs
// ─────────────────────────────────────────────
function StockServicePage({store,currentUser}){
  const [filterSuppliers,setFilterSuppliers]=useState([]);
  const [filterService,setFilterService]=useState("pharmacie"); // "pharmacie" | serviceId
  const [search,setSearch]=useState("");

  // Stock pharmacie par produit = Σ réceptions - Σ transferts vers services
  const getPharmacieStock=(productId)=>{
    const recu   = (store.receptions||[]).reduce((s,r)=>s+(r.items||[]).find(i=>i.productId===productId)?Number((r.items||[]).find(i=>i.productId===productId)?.qty||0):0,0);
    const transf = (store.transfers||[]).reduce((s,t)=>s+(t.items||[]).find(i=>i.productId===productId)?Number((t.items||[]).find(i=>i.productId===productId)?.qty||0):0,0);
    return recu - transf;
  };

  // Stock service = Σ transferts reçus - Σ consommations - Σ retours service
  const getServiceStock=(productId,serviceId)=>{
    const transf = (store.transfers||[]).filter(t=>t.serviceId===serviceId).reduce((s,t)=>s+(t.items||[]).find(i=>i.productId===productId)?Number((t.items||[]).find(i=>i.productId===productId)?.qty||0):0,0);
    const conso  = (store.consumptions||[]).filter(c=>c.serviceId===serviceId).reduce((s,c)=>s+(c.items||[]).find(i=>i.productId===productId)?Number((c.items||[]).find(i=>i.productId===productId)?.qty||0):0,0);
    const retour = (store.svcReturns||[]).filter(r=>r.serviceId===serviceId).reduce((s,r)=>s+(r.items||[]).find(i=>i.productId===productId)?Number((r.items||[]).find(i=>i.productId===productId)?.qty||0):0,0);
    return transf - conso - retour;
  };

  // Produits filtrés
  const allProds = filterSuppliers.length>0
    ? store.products.filter(p=>filterSuppliers.includes(p.supplierId))
    : store.products;
  const filteredProds = search.trim()
    ? allProds.filter(p=>p.name.toLowerCase().includes(search.toLowerCase()))
    : allProds;

  const isPharmacieView = filterService==="pharmacie";

  return(
    <div style={{padding:0}}>
      <PageHeader pageId="stock-service" title="📊 Stock Services" subtitle="Vue temps réel par fournisseur et service"/>
      <div style={{padding:16}}>
        {/* Filtres */}
        <div style={{...card,marginBottom:12,padding:12}}>
          <div style={{fontWeight:700,fontSize:12,color:"#1e293b",marginBottom:8}}>🔍 Filtres</div>
          <div style={{marginBottom:8}}>
            <label style={label}>Vue</label>
            <select style={input} value={filterService} onChange={e=>setFilterService(e.target.value)}>
              <option value="pharmacie">📦 Stock Pharmacie (réceptions − transferts)</option>
              {(store.services||[]).map(s=><option key={s.id} value={s.id}>🏥 {s.name} (transferts − consommations)</option>)}
            </select>
          </div>
          <div style={{marginBottom:8}}>
            <label style={label}>Fournisseur(s)</label>
            <div style={{display:"flex",flexWrap:"wrap",gap:6}}>
              {store.suppliers.map(s=>(
                <button key={s.id} onClick={()=>setFilterSuppliers(f=>f.includes(s.id)?f.filter(x=>x!==s.id):[...f,s.id])}
                  style={{...btn(),background:filterSuppliers.includes(s.id)?"#0891b2":"#f0f9ff",color:filterSuppliers.includes(s.id)?"white":"#0891b2",border:"1px solid #bae6fd",fontSize:11,padding:"4px 10px"}}>
                  {filterSuppliers.includes(s.id)?"✓ ":""}{s.name}
                </button>
              ))}
              {filterSuppliers.length>0&&<button onClick={()=>setFilterSuppliers([])} style={{...btn(),background:"#fee2e2",color:"#ef4444",fontSize:11,padding:"4px 10px"}}>✕ Tout</button>}
            </div>
          </div>
          <input style={{...input}} placeholder="🔍 Rechercher un produit..." value={search} onChange={e=>setSearch(e.target.value)}/>
        </div>

        {/* Tableau stock */}
        <div style={{...card,overflowX:"auto"}}>
          <div style={{fontWeight:700,fontSize:13,color:"#1e293b",marginBottom:10}}>
            {isPharmacieView?"📦 Stock Pharmacie":"🏥 Stock "+((store.services||[]).find(s=>s.id===filterService)?.name||"")}
            <span style={{fontSize:11,color:"#64748b",fontWeight:400,marginLeft:8}}>— {filteredProds.length} produit(s)</span>
          </div>
          {filteredProds.length===0?<div style={{textAlign:"center",padding:30,color:"#94a3b8"}}>Aucun produit.</div>:(
            <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
              <thead>
                <tr>
                  <th style={{background:"#1e3a5f",color:"white",padding:"7px 10px",textAlign:"left",border:"1px solid #1e3a5f"}}>Produit</th>
                  <th style={{background:"#1e3a5f",color:"white",padding:"7px 10px",textAlign:"center",border:"1px solid #1e3a5f"}}>Fournisseur</th>
                  {isPharmacieView?<>
                    <th style={{background:"#065f46",color:"white",padding:"7px 10px",textAlign:"center",border:"1px solid #065f46"}}>Réceptionné</th>
                    <th style={{background:"#7f1d1d",color:"white",padding:"7px 10px",textAlign:"center",border:"1px solid #7f1d1d"}}>Transféré</th>
                  </>:<>
                    <th style={{background:"#065f46",color:"white",padding:"7px 10px",textAlign:"center",border:"1px solid #065f46"}}>Transféré</th>
                    <th style={{background:"#7f1d1d",color:"white",padding:"7px 10px",textAlign:"center",border:"1px solid #7f1d1d"}}>Consommé</th>
                  </>}
                  <th style={{background:"#1d4ed8",color:"white",padding:"7px 10px",textAlign:"center",border:"1px solid #1d4ed8"}}>STOCK</th>
                </tr>
              </thead>
              <tbody>
                {filteredProds.map((p,i)=>{
                  let stockVal,col1,col2;
                  if(isPharmacieView){
                    const recu  =(store.receptions||[]).reduce((s,r)=>s+(r.items||[]).find(it=>it.productId===p.id)?Number((r.items.find(it=>it.productId===p.id)||{}).qty||0):0,0);
                    const transf=(store.transfers||[]).reduce((s,t)=>s+(t.items||[]).find(it=>it.productId===p.id)?Number((t.items.find(it=>it.productId===p.id)||{}).qty||0):0,0);
                    stockVal=recu-transf; col1=recu; col2=transf;
                  } else {
                    const transf =(store.transfers||[]).filter(t=>t.serviceId===filterService).reduce((s,t)=>s+(t.items||[]).find(it=>it.productId===p.id)?Number((t.items.find(it=>it.productId===p.id)||{}).qty||0):0,0);
                    const conso  =(store.consumptions||[]).filter(c=>c.serviceId===filterService).reduce((s,c)=>s+(c.items||[]).find(it=>it.productId===p.id)?Number((c.items.find(it=>it.productId===p.id)||{}).qty||0):0,0);
                    const retour =(store.svcReturns||[]).filter(r=>r.serviceId===filterService).reduce((s,r)=>s+(r.items||[]).find(it=>it.productId===p.id)?Number((r.items.find(it=>it.productId===p.id)||{}).qty||0):0,0);
                    stockVal=transf-conso-retour; col1=transf; col2=conso+retour;
                  }
                  const isAlert=stockVal<=0;
                  return(
                    <tr key={p.id} style={{background:i%2===0?"white":"#f8fafc"}}>
                      <td style={{padding:"6px 10px",border:"1px solid #e2e8f0",fontWeight:500}}>{p.name}</td>
                      <td style={{padding:"6px 10px",border:"1px solid #e2e8f0",textAlign:"center",fontSize:10,color:"#64748b"}}>{store.suppliers.find(s=>s.id===p.supplierId)?.name||"—"}</td>
                      <td style={{padding:"6px 10px",border:"1px solid #e2e8f0",textAlign:"center",color:"#059669",fontWeight:600}}>{col1}</td>
                      <td style={{padding:"6px 10px",border:"1px solid #e2e8f0",textAlign:"center",color:"#dc2626",fontWeight:600}}>{col2}</td>
                      <td style={{padding:"6px 10px",border:"1px solid #e2e8f0",textAlign:"center",fontWeight:800,
                        background:isAlert?"#fee2e2":"#f0fdf4",color:isAlert?"#dc2626":"#059669",fontSize:13}}>
                        {stockVal}
                      </td>
                    </tr>
                  );
                })}
              </tbody>
            </table>
          )}
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// STATISTIQUES PAGE
// ─────────────────────────────────────────────
function StatistiquesPage({store,currentUser}){
  const [tab,setTab]=useState("rotation"); // rotation|user|mouvements|valeur_prescrite|valeur_stock|patient
  const TABS=[
    {id:"rotation",       label:"🔄 Rotation produit"},
    {id:"user",           label:"👤 Activité utilisateur"},
    {id:"mouvements",     label:"📦 Mouvements"},
    {id:"valeur_prescrite",label:"💰 Valeur prescrite"},
    {id:"valeur_stock",   label:"🏦 Valeur stock"},
    {id:"patient",        label:"🏥 Par patient"},
  ];

  // Filtres communs
  const [dateFrom,setDateFrom]=useState(new Date(new Date().getFullYear(),new Date().getMonth(),1).toISOString().split("T")[0]);
  const [dateTo,setDateTo]=useState(new Date().toISOString().split("T")[0]);
  const [selProduct,setSelProduct]=useState("");
  const [selUser,setSelUser]=useState("");
  const [selUsers,setSelUsers]=useState([]);
  const [selService,setSelService]=useState("");
  const [selSupplier,setSelSupplier]=useState("");
  const [showChart,setShowChart]=useState(false);

  const inRange=(ts)=>{
    if(!ts) return true;
    const d = ts?.seconds ? new Date(ts.seconds*1000) : new Date(ts);
    return (!dateFrom||d>=new Date(dateFrom)) && (!dateTo||d<=new Date(dateTo+"T23:59:59"));
  };
  const byUser=(arr,uidField="createdBy")=>selUsers.length>0?arr.filter(x=>selUsers.includes(x[uidField])):arr;

  // ── Helpers export/print ──
  const exportCSV=(rows,headers,filename)=>{
    const lines=[headers.join(","),...rows.map(r=>r.map(v=>'"'+String(v).replace(/"/g,'""')+'"').join(","))];
    const blob=new Blob(["\uFEFF"+lines.join("\n")],{type:"text/csv;charset=utf-8"});
    const a=document.createElement("a"); a.href=URL.createObjectURL(blob); a.download=filename+".csv"; a.click();
  };
  const printTable=(title,headers,rows)=>{
    const html="<!DOCTYPE html><html><head><meta charset='utf-8'><title>"+title+"</title>"+
      "<style>body{font-family:Arial,sans-serif;font-size:11px;padding:20px}"+
      "h2{color:#312e81;margin-bottom:12px}"+
      "table{width:100%;border-collapse:collapse}"+
      "th{background:#312e81;color:white;padding:7px 10px;text-align:left}"+
      "td{padding:5px 10px;border-bottom:1px solid #e2e8f0}"+
      "tr:nth-child(even){background:#f8fafc}"+
      ".total{font-weight:bold;background:#eef2ff}"+
      "</style></head><body>"+
      "<h2>"+title+"</h2>"+
      "<p style='font-size:10px;color:#64748b;margin-bottom:8px'>Du "+dateFrom+" au "+dateTo+"</p>"+
      "<table><thead><tr>"+headers.map(h=>"<th>"+h+"</th>").join("")+"</tr></thead><tbody>"+
      rows.map(r=>"<tr>"+r.map(v=>"<td>"+v+"</td>").join("")+"</tr>").join("")+
      "</tbody></table></body></html>";
    const blob=new Blob([html],{type:"text/html;charset=utf-8"});
    const win=window.open(URL.createObjectURL(blob),"_blank");
    if(win) win.addEventListener("load",()=>setTimeout(()=>win.print(),400));
  };

  // ══ 1. ROTATION PRODUIT ══
  const RotationTab=()=>{
    const prod=store.products.find(p=>p.id===selProduct);
    if(!selProduct) return(
      <div>
        <div style={{marginBottom:10}}><label style={label}>Choisir un produit</label>
          <select style={input} value={selProduct} onChange={e=>setSelProduct(e.target.value)}>
            <option value="">— Sélectionner —</option>
            {store.products.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
          </select>
        </div>
      </div>
    );
    // Entrées (bons d'entrée)
    const ents=store.entries.filter(e=>inRange(e.createdAt)&&(e.items||[]).some(i=>i.productId===selProduct));
    const totalEnt=ents.reduce((s,e)=>s+((e.items||[]).find(i=>i.productId===selProduct)?.qty||0)*1,0);
    // Réceptions
    const recs=store.receptions.filter(r=>inRange(r.createdAt)&&(r.items||[]).some(i=>i.productId===selProduct));
    const totalRec=recs.reduce((s,r)=>s+((r.items||[]).find(i=>i.productId===selProduct)?.qty||0)*1,0);
    // Transferts
    const trans=store.transfers.filter(t=>inRange(t.createdAt)&&(t.items||[]).some(i=>i.productId===selProduct));
    const totalTrans=trans.reduce((s,t)=>s+((t.items||[]).find(i=>i.productId===selProduct)?.qty||0)*1,0);
    // Consommations
    const consos=store.consumptions.filter(c=>inRange(c.createdAt)&&(c.items||[]).some(i=>i.productId===selProduct));
    const totalConso=consos.reduce((s,c)=>s+((c.items||[]).find(i=>i.productId===selProduct)?.qty||0)*1,0);
    // Retours
    const rets=store.returns.filter(r=>inRange(r.createdAt)&&(r.items||[]).some(i=>i.productId===selProduct));
    const totalRet=rets.reduce((s,r)=>s+((r.items||[]).find(i=>i.productId===selProduct)?.qty||0)*1,0);
    const stockActuel=store.stock[selProduct]||0;
    const rows=[["Bons d'entrée",totalEnt],["Réceptions service",totalRec],["Transferts",totalTrans],["Consommations",totalConso],["Bons de retour",totalRet],["Stock actuel (inventaire)",stockActuel]];
    return(
      <div>
        <div style={{marginBottom:10}}><label style={label}>Produit</label>
          <select style={input} value={selProduct} onChange={e=>setSelProduct(e.target.value)}>
            <option value="">— Sélectionner —</option>
            {store.products.map(p=><option key={p.id} value={p.id}>{p.name}</option>)}
          </select>
        </div>
        <div style={{fontWeight:700,fontSize:14,color:"#312e81",marginBottom:10}}>🔄 {prod?.name}</div>
        <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:12}}>
          {[["📥 Entrées",totalEnt,"#059669"],["📦 Réceptions",totalRec,"#0891b2"],["🔄 Transferts",totalTrans,"#7c3aed"],
            ["💉 Consommés",totalConso,"#dc2626"],["↩️ Retours",totalRet,"#d97706"],["📦 Stock",stockActuel,"#1d4ed8"]].map(([l,v,c])=>(
            <div key={l} style={{...card,padding:12,textAlign:"center",border:"1px solid "+c+"33"}}>
              <div style={{fontWeight:800,fontSize:22,color:c}}>{v}</div>
              <div style={{fontSize:11,color:"#64748b"}}>{l}</div>
            </div>
          ))}
        </div>
        <div style={{display:"flex",gap:8,marginBottom:8}}>
          <button onClick={()=>printTable("Rotation — "+prod?.name,["Indicateur","Quantité"],rows)} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>🖨️ Imprimer</button>
          <button onClick={()=>exportCSV(rows,["Indicateur","Quantité"],"rotation_"+prod?.name)} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #86efac",fontSize:12}}>⬇️ CSV</button>
        </div>
      </div>
    );
  };

  // ══ 2. ACTIVITÉ UTILISATEUR ══
  const UserTab=()=>{
    const user=store.users.find(u=>u.id===selUser);
    if(!selUser) return <div><label style={label}>Choisir un utilisateur</label><select style={input} value={selUser} onChange={e=>setSelUser(e.target.value)}><option value="">— Sélectionner —</option>{store.users.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}</select></div>;
    const acts=(store.activities||[]).filter(a=>a.userId===selUser&&inRange(a.createdAt));
    const rows=acts.map(a=>[new Date((a.createdAt?.seconds||0)*1000).toLocaleString("fr-FR"),a.action,a.details||"—"]);
    return(
      <div>
        <div style={{marginBottom:10}}><label style={label}>Utilisateur</label><select style={input} value={selUser} onChange={e=>setSelUser(e.target.value)}><option value="">—</option>{store.users.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}</select></div>
        <div style={{fontWeight:700,fontSize:14,color:"#312e81",marginBottom:8}}>👤 {user?.name} — {acts.length} action(s)</div>
        <div style={{maxHeight:300,overflowY:"auto",...card}}>
          {acts.length===0?<div style={{padding:20,textAlign:"center",color:"#94a3b8"}}>Aucune activité sur cette période.</div>:
          acts.map((a,i)=>(
            <div key={i} style={{padding:"8px 12px",borderBottom:"1px solid #f1f5f9",fontSize:11}}>
              <div style={{fontWeight:600,color:"#1e293b"}}>{a.details||"—"}</div>
              <div style={{color:"#94a3b8",fontSize:10}}>{new Date((a.createdAt?.seconds||0)*1000).toLocaleString("fr-FR")} · <span style={{color:a.action==="create"?"#059669":a.action==="delete"?"#ef4444":"#d97706"}}>{a.action}</span></div>
            </div>
          ))}
        </div>
        <div style={{display:"flex",gap:8,marginTop:8}}>
          <button onClick={()=>printTable("Activité — "+user?.name,["Date","Action","Détail"],rows)} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>🖨️ Imprimer</button>
          <button onClick={()=>exportCSV(rows,["Date","Action","Détail"],"activite_"+user?.name)} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #86efac",fontSize:12}}>⬇️ CSV</button>
        </div>
      </div>
    );
  };

  // ══ 3. MOUVEMENTS ══
  const MouvementsTab=()=>{
    const [typeFilter,setTypeFilter]=useState("tous"); // tous|receptions|transferts|consommations
    const getItems=(arr,field="createdBy")=>byUser(arr.filter(x=>inRange(x.createdAt)),field)
      .flatMap(x=>(x.items||[]).map(it=>({
        date:new Date((x.createdAt?.seconds||0)*1000).toLocaleDateString("fr-FR"),
        type:field==="receivedBy"?"Réception":field==="transferredBy"?"Transfert":"Consommation",
        produit:it.productName||store.products.find(p=>p.id===it.productId)?.name||"—",
        qty:Number(it.qty||0),
        user:x[field+"Name"]||x.consumedByName||"—",
        service:x.serviceName||"—",
      })));
    const allRows=[
      ...(typeFilter==="tous"||typeFilter==="receptions"?getItems(store.receptions,"receivedBy"):[]),
      ...(typeFilter==="tous"||typeFilter==="transferts"?getItems(store.transfers,"transferredBy"):[]),
      ...(typeFilter==="tous"||typeFilter==="consommations"?getItems(store.consumptions,"consumedBy"):[]),
    ].sort((a,b)=>a.date.localeCompare(b.date));
    // Agrégation par produit pour le diagramme
    const byProd={};
    allRows.forEach(r=>{ byProd[r.produit]=(byProd[r.produit]||0)+r.qty; });
    const chartData=Object.entries(byProd).sort((a,b)=>b[1]-a[1]).slice(0,15);
    const maxVal=Math.max(...chartData.map(x=>x[1]),1);
    const tableRows=allRows.map(r=>[r.date,r.type,r.produit,r.qty,r.user,r.service]);
    return(
      <div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
          <div><label style={label}>Type</label>
            <select style={input} value={typeFilter} onChange={e=>setTypeFilter(e.target.value)}>
              <option value="tous">Tous</option><option value="receptions">Réceptions</option>
              <option value="transferts">Transferts</option><option value="consommations">Consommations</option>
            </select>
          </div>
          <div><label style={label}>Utilisateur(s)</label>
            <select style={input} value={selUsers[0]||""} onChange={e=>setSelUsers(e.target.value?[e.target.value]:[])}>
              <option value="">Tous</option>{store.users.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}
            </select>
          </div>
        </div>
        {/* Diagramme barres */}
        <div style={{...card,marginBottom:10,padding:12}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:8}}>
            <div style={{fontWeight:700,fontSize:12,color:"#312e81"}}>📊 Top produits — {allRows.length} mouvement(s)</div>
            <button onClick={()=>setShowChart(v=>!v)} style={{...btn(),background:"#eef2ff",color:"#4f46e5",fontSize:11,padding:"4px 10px"}}>{showChart?"📋 Tableau":"📊 Diagramme"}</button>
          </div>
          {showChart?(
            <div style={{overflowX:"auto"}}>
              {chartData.map(([name,val])=>(
                <div key={name} style={{marginBottom:5}}>
                  <div style={{display:"flex",alignItems:"center",gap:8}}>
                    <div style={{fontSize:10,width:160,color:"#1e293b",overflow:"hidden",textOverflow:"ellipsis",whiteSpace:"nowrap",flexShrink:0}}>{name}</div>
                    <div style={{flex:1,background:"#e0e7ff",borderRadius:4,height:18,overflow:"hidden"}}>
                      <div style={{width:(val/maxVal*100)+"%",background:"linear-gradient(90deg,#4f46e5,#818cf8)",height:"100%",borderRadius:4,display:"flex",alignItems:"center",paddingLeft:4}}>
                        <span style={{fontSize:9,color:"white",fontWeight:700}}>{val}</span>
                      </div>
                    </div>
                  </div>
                </div>
              ))}
              {chartData.length===0&&<div style={{textAlign:"center",color:"#94a3b8",padding:20}}>Aucune donnée</div>}
            </div>
          ):(
            <div style={{maxHeight:300,overflowY:"auto"}}>
              {allRows.length===0?<div style={{textAlign:"center",color:"#94a3b8",padding:20}}>Aucun mouvement.</div>:
              <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
                <thead><tr>{["Date","Type","Produit","Qté","Utilisateur","Service"].map(h=><th key={h} style={{background:"#312e81",color:"white",padding:"5px 8px",textAlign:"left"}}>{h}</th>)}</tr></thead>
                <tbody>{allRows.map((r,i)=><tr key={i} style={{background:i%2===0?"white":"#f8fafc"}}>{[r.date,r.type,r.produit,r.qty,r.user,r.service].map((v,j)=><td key={j} style={{padding:"4px 8px",borderBottom:"1px solid #f1f5f9"}}>{v}</td>)}</tr>)}</tbody>
              </table>}
            </div>
          )}
        </div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={()=>printTable("Mouvements",["Date","Type","Produit","Qté","Utilisateur","Service"],tableRows)} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>🖨️ Imprimer</button>
          <button onClick={()=>exportCSV(tableRows,["Date","Type","Produit","Qté","Utilisateur","Service"],"mouvements")} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #86efac",fontSize:12}}>⬇️ CSV</button>
        </div>
      </div>
    );
  };

  // ══ 4. VALEUR PRESCRITE ══
  const ValeurPrescrite=()=>{
    const consos=byUser(store.consumptions.filter(c=>inRange(c.createdAt)),"consumedBy");
    const rows=consos.flatMap(c=>(c.items||[]).map(it=>{
      const prod=store.products.find(p=>p.id===it.productId);
      const valeur=Number(it.qty||0)*Number(prod?.price||0);
      return [new Date((c.createdAt?.seconds||0)*1000).toLocaleDateString("fr-FR"),c.serviceName||"—",it.productName||"—",it.qty,Number(prod?.price||0).toLocaleString("fr-FR"),valeur.toLocaleString("fr-FR"),c.consumedByName||"—",c.patientName||"—"];
    }));
    const total=consos.reduce((s,c)=>(c.items||[]).reduce((ss,it)=>{const prod=store.products.find(p=>p.id===it.productId);return ss+Number(it.qty||0)*Number(prod?.price||0);},s),0);
    return(
      <div>
        <div style={{marginBottom:10}}><label style={label}>Utilisateur(s)</label>
          <select style={input} value={selUsers[0]||""} onChange={e=>setSelUsers(e.target.value?[e.target.value]:[])}>
            <option value="">Tous</option>{store.users.map(u=><option key={u.id} value={u.id}>{u.name}</option>)}
          </select>
        </div>
        <div style={{...card,background:"linear-gradient(135deg,#312e81,#4f46e5)",padding:14,marginBottom:12,textAlign:"center"}}>
          <div style={{fontSize:11,color:"rgba(255,255,255,0.7)"}}>Valeur totale prescrite</div>
          <div style={{fontWeight:800,fontSize:24,color:"white"}}>{total.toLocaleString("fr-FR")} FCFA</div>
          <div style={{fontSize:10,color:"rgba(255,255,255,0.6)"}}>{rows.length} ligne(s) · du {dateFrom} au {dateTo}</div>
        </div>
        <div style={{maxHeight:280,overflowY:"auto",...card,marginBottom:8}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
            <thead><tr>{["Date","Service","Produit","Qté","P.U.","Valeur","Agent","Patient"].map(h=><th key={h} style={{background:"#312e81",color:"white",padding:"5px 6px",textAlign:"left",fontSize:10}}>{h}</th>)}</tr></thead>
            <tbody>{rows.map((r,i)=><tr key={i} style={{background:i%2===0?"white":"#f8fafc"}}>{r.map((v,j)=><td key={j} style={{padding:"4px 6px",borderBottom:"1px solid #f1f5f9",fontSize:10}}>{v}</td>)}</tr>)}</tbody>
          </table>
        </div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={()=>printTable("Valeur prescrite",["Date","Service","Produit","Qté","P.U.","Valeur","Agent","Patient"],rows)} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>🖨️ Imprimer</button>
          <button onClick={()=>exportCSV(rows,["Date","Service","Produit","Qté","P.U.","Valeur","Agent","Patient"],"valeur_prescrite")} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #86efac",fontSize:12}}>⬇️ CSV</button>
        </div>
      </div>
    );
  };

  // ══ 5. VALEUR STOCK ══
  const ValeurStock=()=>{
    const [view,setView]=useState("pharmacie");
    // Stock pharmacie = prix × stockQty (inventaire)
    const pharmacieRows=store.products.filter(p=>!selSupplier||p.supplierId===selSupplier).map(p=>{
      const qty=store.stock[p.id]||0;
      const val=qty*Number(p.price||0);
      return {name:p.name,supplier:store.suppliers.find(s=>s.id===p.supplierId)?.name||"—",qty,price:p.price||0,val};
    }).filter(r=>r.qty>0);
    const pharmTotal=pharmacieRows.reduce((s,r)=>s+r.val,0);
    // Stock service = svcStock × prix
    const svcRows=view!=="pharmacie"?(store.services||[]).filter(s=>!view||view==="tous"||s.id===view).flatMap(svc=>
      Object.keys(store.svcStock||{}).filter(k=>k.startsWith(svc.id+"_")).map(k=>{
        const prodId=k.split("_")[1];
        const prod=store.products.find(p=>p.id===prodId);
        const qty=store.svcStock[k]||0;
        return {service:svc.name,name:prod?.name||"—",qty,price:prod?.price||0,val:qty*(prod?.price||0)};
      }).filter(r=>r.qty>0)
    ):[];
    const svcTotal=svcRows.reduce((s,r)=>s+r.val,0);
    const isPharm=view==="pharmacie";
    const rows=isPharm?pharmacieRows.map(r=>[r.name,r.supplier,r.qty,r.price.toLocaleString("fr-FR"),r.val.toLocaleString("fr-FR")]):
      svcRows.map(r=>[r.service,r.name,r.qty,r.price.toLocaleString("fr-FR"),r.val.toLocaleString("fr-FR")]);
    const total=isPharm?pharmTotal:svcTotal;
    const headers=isPharm?["Produit","Fournisseur","Stock","Prix unit.","Valeur (FCFA)"]:["Service","Produit","Stock","Prix unit.","Valeur (FCFA)"];
    return(
      <div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
          <div><label style={label}>Vue</label>
            <select style={input} value={view} onChange={e=>setView(e.target.value)}>
              <option value="pharmacie">📦 Stock Pharmacie</option>
              <option value="tous">🏥 Tous les services</option>
              {(store.services||[]).map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          </div>
          {isPharm&&<div><label style={label}>Fournisseur</label>
            <select style={input} value={selSupplier} onChange={e=>setSelSupplier(e.target.value)}>
              <option value="">Tous</option>{store.suppliers.map(s=><option key={s.id} value={s.id}>{s.name}</option>)}
            </select>
          </div>}
        </div>
        <div style={{...card,background:"linear-gradient(135deg,#1d4ed8,#3b82f6)",padding:14,marginBottom:12,textAlign:"center"}}>
          <div style={{fontSize:11,color:"rgba(255,255,255,0.7)"}}>Valeur totale du stock</div>
          <div style={{fontWeight:800,fontSize:24,color:"white"}}>{total.toLocaleString("fr-FR")} FCFA</div>
          <div style={{fontSize:10,color:"rgba(255,255,255,0.6)"}}>{rows.length} produit(s)</div>
        </div>
        <div style={{maxHeight:280,overflowY:"auto",...card,marginBottom:8}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
            <thead><tr>{headers.map(h=><th key={h} style={{background:"#1d4ed8",color:"white",padding:"5px 8px",textAlign:"left"}}>{h}</th>)}</tr></thead>
            <tbody>{rows.map((r,i)=><tr key={i} style={{background:i%2===0?"white":"#eff6ff"}}>{r.map((v,j)=><td key={j} style={{padding:"4px 8px",borderBottom:"1px solid #f1f5f9"}}>{v}</td>)}</tr>)}</tbody>
          </table>
        </div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={()=>printTable("Valeur Stock",headers,rows)} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>🖨️ Imprimer</button>
          <button onClick={()=>exportCSV(rows,headers,"valeur_stock")} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #86efac",fontSize:12}}>⬇️ CSV</button>
        </div>
      </div>
    );
  };

  // ══ 6. PAR PATIENT ══
  const PatientTab=()=>{
    const [searchPat,setSearchPat]=useState("");
    const consos=store.consumptions.filter(c=>inRange(c.createdAt)&&(c.patientName||c.patientId));
    // Grouper par patient
    const byPat={};
    consos.forEach(c=>{
      const key=(c.patientName||"")+"||"+(c.patientId||"");
      if(!byPat[key]) byPat[key]={name:c.patientName||"—",id:c.patientId||"—",items:[],total:0,conso:[]};
      (c.items||[]).forEach(it=>{
        const prod=store.products.find(p=>p.id===it.productId);
        const val=Number(it.qty||0)*Number(prod?.price||0);
        byPat[key].total+=val;
        const ex=byPat[key].items.find(x=>x.prodId===it.productId);
        if(ex) ex.qty+=Number(it.qty||0);
        else byPat[key].items.push({prodId:it.productId,name:it.productName||"—",qty:Number(it.qty||0),val});
      });
      byPat[key].conso.push(c);
    });
    const patients=Object.values(byPat).filter(p=>!searchPat||p.name.toLowerCase().includes(searchPat.toLowerCase())||p.id.includes(searchPat));
    const [selPat,setSelPat]=useState(null);
    const rows=selPat?selPat.items.map(i=>[i.name,i.qty,Number(store.products.find(p=>p.id===i.prodId)?.price||0).toLocaleString("fr-FR"),i.val.toLocaleString("fr-FR")]):
      patients.map(p=>[p.name,p.id,p.conso.length,p.items.reduce((s,i)=>s+i.qty,0),p.total.toLocaleString("fr-FR")]);
    const headers=selPat?["Produit","Qté","Prix unit.","Valeur (FCFA)"]:["Patient","N° Dossier","Prescriptions","Qté totale","Valeur (FCFA)"];
    return(
      <div>
        <input style={{...input,marginBottom:10}} placeholder="🔍 Rechercher un patient..."
          value={searchPat} onChange={e=>setSearchPat(e.target.value)}/>
        {selPat?(
          <div>
            <button onClick={()=>setSelPat(null)} style={{...btn(),background:"#eef2ff",color:"#4f46e5",marginBottom:8,fontSize:12}}>← Retour liste</button>
            <div style={{fontWeight:700,fontSize:14,color:"#312e81",marginBottom:8}}>🏥 {selPat.name} {selPat.id!=="—"?"· "+selPat.id:""}</div>
            <div style={{...card,marginBottom:8,padding:10,background:"#eef2ff",textAlign:"center"}}>
              <div style={{fontSize:11,color:"#4f46e5"}}>Valeur totale</div>
              <div style={{fontWeight:800,fontSize:18,color:"#312e81"}}>{selPat.total.toLocaleString("fr-FR")} FCFA</div>
            </div>
          </div>
        ):(
          <div style={{fontWeight:700,fontSize:13,color:"#312e81",marginBottom:8}}>{patients.length} patient(s) trouvé(s)</div>
        )}
        <div style={{maxHeight:300,overflowY:"auto",...card,marginBottom:8}}>
          <table style={{width:"100%",borderCollapse:"collapse",fontSize:11}}>
            <thead><tr>{headers.map(h=><th key={h} style={{background:"#312e81",color:"white",padding:"5px 8px",textAlign:"left"}}>{h}</th>)}</tr></thead>
            <tbody>
              {(selPat?selPat.items:patients).map((r,i)=>(
                <tr key={i} style={{background:i%2===0?"white":"#f8fafc",cursor:selPat?"default":"pointer"}}
                  onClick={()=>!selPat&&setSelPat(r)}>
                  {(selPat?[r.name,r.qty,Number(store.products.find(p=>p.id===r.prodId)?.price||0).toLocaleString("fr-FR"),r.val.toLocaleString("fr-FR")]:
                    [r.name,r.id,r.conso.length,r.items.reduce((s,x)=>s+x.qty,0),r.total.toLocaleString("fr-FR")])
                    .map((v,j)=><td key={j} style={{padding:"5px 8px",borderBottom:"1px solid #f1f5f9"}}>{v}</td>)}
                  {!selPat&&<td style={{padding:"5px 8px",borderBottom:"1px solid #f1f5f9",color:"#94a3b8"}}>›</td>}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={()=>printTable(selPat?"Détail — "+selPat.name:"Consommations par patient",headers,rows)} style={{...btn(),background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",fontSize:12}}>🖨️ Imprimer</button>
          <button onClick={()=>exportCSV(rows,headers,"patients")} style={{...btn(),background:"#f0fdf4",color:"#059669",border:"1px solid #86efac",fontSize:12}}>⬇️ CSV</button>
        </div>
      </div>
    );
  };

  return(
    <div style={{padding:0}}>
      <PageHeader pageId="statistiques" title="📈 Statistiques" subtitle="Analyses et rapports"/>
      <div style={{padding:16}}>
        {/* Filtres dates communs */}
        <div style={{...card,marginBottom:12,padding:12}}>
          <div style={{fontWeight:700,fontSize:12,color:"#312e81",marginBottom:8}}>📅 Période</div>
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
            <div><label style={label}>Du</label><input type="date" style={input} value={dateFrom} onChange={e=>setDateFrom(e.target.value)}/></div>
            <div><label style={label}>Au</label><input type="date" style={input} value={dateTo} onChange={e=>setDateTo(e.target.value)}/></div>
          </div>
        </div>

        {/* Onglets */}
        <div style={{display:"flex",gap:4,flexWrap:"wrap",marginBottom:12}}>
          {TABS.map(t=>(
            <button key={t.id} onClick={()=>setTab(t.id)}
              style={{...btn(),background:tab===t.id?"#4f46e5":"#f0f0ff",color:tab===t.id?"white":"#4f46e5",
                border:"1px solid "+(tab===t.id?"#4f46e5":"#c7d2fe"),fontSize:11,padding:"6px 10px",fontWeight:tab===t.id?700:400}}>
              {t.label}
            </button>
          ))}
        </div>

        {/* Contenu onglet */}
        <div style={{...card,padding:14}}>
          {tab==="rotation"         && <RotationTab/>}
          {tab==="user"             && <UserTab/>}
          {tab==="mouvements"       && <MouvementsTab/>}
          {tab==="valeur_prescrite" && <ValeurPrescrite/>}
          {tab==="valeur_stock"     && <ValeurStock/>}
          {tab==="patient"          && <PatientTab/>}
        </div>
      </div>
    </div>
  );
}

function ActivitiesPage({store, currentUser}){
  const [filter, setFilter] = useState("all");
  const [search, setSearch] = useState("");
  const [dateFrom, setDateFrom] = useState("");
  const [dateTo, setDateTo] = useState("");
  const [selected, setSelected] = useState(null); // activité sélectionnée pour détails

  const ENTITY_LABELS = {
    entry:"Bon d'entrée", return:"Bon de retour", inventory:"Inventaire",
    invoice:"Facture", product:"Produit", supplier:"Fournisseur",
    depot:"Dépôt", user:"Utilisateur", other:"Autre",
  };
  const ENTITY_ICONS = {
    entry:"📥", return:"↩️", inventory:"🗂️", invoice:"📊",
    product:"💊", supplier:"🏢", depot:"🏭", user:"👤", other:"📌",
  };
  const ACTION_COLORS = {
    create:{ bg:"#dcfce7", color:"#059669", label:"Création",   icon:"➕" },
    update:{ bg:"#fef3c7", color:"#d97706", label:"Modification", icon:"✏️" },
    delete:{ bg:"#fee2e2", color:"#ef4444", label:"Suppression", icon:"🗑️" },
  };

  // Retrouver les données liées à l'activité
  const getRelatedData = (a) => {
    if(!a?.entity || !a?.entityId) return null;
    switch(a.entity){
      case "entry":     return store.entries.find(x=>x.id===a.entityId);
      case "return":    return store.returns.find(x=>x.id===a.entityId);
      case "inventory": return store.inventories.find(x=>x.id===a.entityId);
      case "invoice":   return store.invoices.find(x=>x.id===a.entityId);
      case "product":   return store.products.find(x=>x.id===a.entityId);
      case "supplier":  return store.suppliers.find(x=>x.id===a.entityId);
      case "depot":     return store.depots.find(x=>x.id===a.entityId);
      case "user":      return store.users.find(x=>x.id===a.entityId);
      default: return null;
    }
  };

  const activities = (store.activities||[]).filter(a=>{
    if(filter!=="all" && a.action!==filter) return false;
    if(search && !a.details?.toLowerCase().includes(search.toLowerCase()) &&
       !a.userName?.toLowerCase().includes(search.toLowerCase())) return false;
    if(dateFrom && a.createdAt?.seconds){
      if(new Date(a.createdAt.seconds*1000) < new Date(dateFrom)) return false;
    }
    if(dateTo && a.createdAt?.seconds){
      if(new Date(a.createdAt.seconds*1000) > new Date(dateTo+"T23:59:59")) return false;
    }
    return true;
  });

  const stats = {
    create: (store.activities||[]).filter(a=>a.action==="create").length,
    update: (store.activities||[]).filter(a=>a.action==="update").length,
    delete: (store.activities||[]).filter(a=>a.action==="delete").length,
  };

  const fmtDate = (ts) => ts?.seconds
    ? new Date(ts.seconds*1000).toLocaleString("fr-FR",{day:"2-digit",month:"2-digit",year:"numeric",hour:"2-digit",minute:"2-digit",second:"2-digit"})
    : "—";

  // Rendu des détails selon le type d'entité
  const renderDetails = (a) => {
    const rel = getRelatedData(a);
    const ac = ACTION_COLORS[a.action]||ACTION_COLORS.update;
    return(
      <div>
        {/* En-tête */}
        <div style={{background:ac.bg,borderRadius:10,padding:"12px 16px",marginBottom:14,display:"flex",alignItems:"center",gap:10}}>
          <span style={{fontSize:28}}>{ac.icon}</span>
          <div>
            <div style={{fontWeight:800,color:ac.color,fontSize:15}}>{ac.label}</div>
            <div style={{fontSize:12,color:"#64748b"}}>{ENTITY_ICONS[a.entity]||"📌"} {ENTITY_LABELS[a.entity]||a.entity}</div>
          </div>
        </div>

        {/* Infos principales */}
        <div style={{display:"flex",flexDirection:"column",gap:8,marginBottom:14}}>
          {[
            ["👤 Utilisateur",  a.userName||"—"],
            ["🕐 Date & heure", fmtDate(a.createdAt)],
            ["📝 Description",  a.details||"—"],
            ["🔑 ID entité",    a.entityId||"—"],
          ].map(([label,value])=>(
            <div key={label} style={{background:"#f8fafc",borderRadius:8,padding:"8px 12px"}}>
              <div style={{fontSize:10,color:"#94a3b8",fontWeight:600,marginBottom:2}}>{label}</div>
              <div style={{fontSize:13,color:"#1e293b",wordBreak:"break-all"}}>{value}</div>
            </div>
          ))}
          {/* Ancien → Nouveau nom si disponible */}
          {(a.oldName||a.newName)&&a.oldName!==a.newName&&(
            <div style={{background:"#fef3c7",borderRadius:8,padding:"10px 12px",border:"1px solid #fcd34d"}}>
              <div style={{fontSize:10,color:"#92400e",fontWeight:600,marginBottom:6}}>✏️ CHANGEMENT DE NOM</div>
              <div style={{display:"flex",alignItems:"center",gap:8,fontSize:13}}>
                <span style={{background:"#fee2e2",color:"#b91c1c",padding:"3px 10px",borderRadius:6,fontWeight:600}}>{a.oldName||"—"}</span>
                <span style={{color:"#92400e",fontWeight:700}}>→</span>
                <span style={{background:"#dcfce7",color:"#15803d",padding:"3px 10px",borderRadius:6,fontWeight:600}}>{a.newName||"—"}</span>
              </div>
            </div>
          )}
          {/* Ancien → Nouveau rôle si disponible */}
          {(a.oldRole||a.newRole)&&a.oldRole!==a.newRole&&(
            <div style={{background:"#f0f9ff",borderRadius:8,padding:"10px 12px",border:"1px solid #bae6fd"}}>
              <div style={{fontSize:10,color:"#0369a1",fontWeight:600,marginBottom:6}}>🛡️ CHANGEMENT DE RÔLE</div>
              <div style={{display:"flex",alignItems:"center",gap:8,fontSize:13}}>
                <span style={{background:"#fee2e2",color:"#b91c1c",padding:"3px 10px",borderRadius:6,fontWeight:600}}>{a.oldRole||"—"}</span>
                <span style={{color:"#0369a1",fontWeight:700}}>→</span>
                <span style={{background:"#dcfce7",color:"#15803d",padding:"3px 10px",borderRadius:6,fontWeight:600}}>{a.newRole||"—"}</span>
              </div>
            </div>
          )}
          {/* Ancien nom supprimé */}
          {a.action==="delete"&&a.oldName&&(
            <div style={{background:"#fee2e2",borderRadius:8,padding:"10px 12px",border:"1px solid #fca5a5"}}>
              <div style={{fontSize:10,color:"#b91c1c",fontWeight:600,marginBottom:4}}>🗑️ ÉLÉMENT SUPPRIMÉ</div>
              <div style={{fontSize:13,color:"#7f1d1d",fontWeight:700}}>{a.oldName}{a.oldRole?` (${a.oldRole})`:""}</div>
            </div>
          )}
        </div>

        {/* Données liées si disponibles */}
        {rel && (
          <div style={{marginBottom:8}}>
            <div style={{fontWeight:700,fontSize:13,color:"#1e293b",marginBottom:8}}>
              📋 Données associées {a.action==="delete"?"(avant suppression)":"(actuelles)"}
            </div>
            <div style={{background:"#f1f5f9",borderRadius:8,padding:12,fontSize:11,fontFamily:"monospace",color:"#334155",maxHeight:220,overflowY:"auto",wordBreak:"break-all"}}>
              {a.entity==="entry"||a.entity==="return" ? (
                <div style={{fontFamily:"sans-serif",fontSize:12}}>
                  <div style={{marginBottom:6}}><b>Référence :</b> {rel.reference||"—"}</div>
                  <div style={{marginBottom:6}}><b>Date :</b> {rel.date||"—"}</div>
                  <div style={{marginBottom:6}}><b>Dépôt :</b> {store.depots.find(d=>d.id===rel.depotId)?.name||rel.depotId||"—"}</div>
                  <div style={{marginBottom:6}}><b>Articles ({rel.items?.length||0}) :</b></div>
                  {(rel.items||[]).map((it,i)=>{
                    const prod = store.products.find(p=>p.id===it.productId);
                    return <div key={i} style={{paddingLeft:12,color:"#475569",marginBottom:3}}>
                      • {prod?.name||it.productId} — Qté : {it.qty} — Prix : {Number(it.unitPrice||0).toLocaleString("fr-FR")} FCFA{it.lot?` — Lot : ${it.lot}`:""}
                    </div>;
                  })}
                </div>
              ) : a.entity==="inventory" ? (
                <div style={{fontFamily:"sans-serif",fontSize:12}}>
                  <div style={{marginBottom:6}}><b>Mois :</b> {rel.month||"—"}</div>
                  <div style={{marginBottom:6}}><b>Total vendu :</b> {rel.totalSold||0} unités</div>
                  <div style={{marginBottom:6}}><b>Statut :</b> {rel.validated?"🔒 Validé":"⏳ En cours"}</div>
                  <div style={{marginBottom:6}}><b>Produits ({rel.data?.length||0}) :</b></div>
                  {(rel.data||[]).filter(r=>r.sold>0).slice(0,10).map((r,i)=>(
                    <div key={i} style={{paddingLeft:12,color:"#475569",marginBottom:3}}>
                      • {r.product?.name||"—"} — Vendus : {r.sold} — Stock : {r.nw}
                    </div>
                  ))}
                  {(rel.data||[]).filter(r=>r.sold>0).length>10&&<div style={{color:"#94a3b8",paddingLeft:12}}>...et {(rel.data||[]).filter(r=>r.sold>0).length-10} autres</div>}
                </div>
              ) : a.entity==="invoice" ? (
                <div style={{fontFamily:"sans-serif",fontSize:12}}>
                  <div style={{marginBottom:6}}><b>Référence :</b> {rel.reference||"—"}</div>
                  <div style={{marginBottom:6}}><b>Total :</b> {Number(rel.total||0).toLocaleString("fr-FR")} FCFA</div>
                  <div style={{marginBottom:6}}><b>Statut :</b> {rel.status||"—"}</div>
                </div>
              ) : a.entity==="product" ? (
                <div style={{fontFamily:"sans-serif",fontSize:12}}>
                  <div style={{marginBottom:6}}><b>Nom :</b> {rel.name||"—"}</div>
                  <div style={{marginBottom:6}}><b>Prix :</b> {Number(rel.price||0).toLocaleString("fr-FR")} FCFA</div>
                  <div style={{marginBottom:6}}><b>Unité :</b> {rel.unit||"—"}</div>
                  <div style={{marginBottom:6}}><b>Stock :</b> {store.stock[rel.id]||0}</div>
                </div>
              ) : a.entity==="user" ? (
                <div style={{fontFamily:"sans-serif",fontSize:12}}>
                  <div style={{marginBottom:6}}><b>Nom :</b> {rel.name||"—"}</div>
                  <div style={{marginBottom:6}}><b>Email :</b> {rel.email||"—"}</div>
                  <div style={{marginBottom:6}}><b>Rôle :</b> {ROLES[rel.role]?.label||rel.role||"—"}</div>
                </div>
              ) : (
                <pre style={{fontSize:11,whiteSpace:"pre-wrap"}}>{JSON.stringify(rel,null,2)}</pre>
              )}
            </div>
          </div>
        )}
        {!rel && a.action==="delete" && (
          <div style={{background:"#fef3c7",borderRadius:8,padding:"10px 12px",fontSize:12,color:"#92400e"}}>
            ⚠️ Les données ont été supprimées et ne sont plus disponibles.
          </div>
        )}
      </div>
    );
  };

  return(
    <div style={{padding:0}}>
      {/* Modal détail activité */}
      <Modal open={!!selected} onClose={()=>setSelected(null)}
        title={"📜 Détail de l'activité"}>
        {selected && renderDetails(selected)}
      </Modal>

      <PageHeader pageId="activites" title="📜 Journal d'activité" subtitle="Historique complet des actions utilisateurs"/>
      <div style={{padding:16}}>

        {/* Stats rapides */}
        <div style={{display:"grid",gridTemplateColumns:"repeat(3,1fr)",gap:8,marginBottom:14}}>
          {[["create","Créations","#dcfce7","#059669"],["update","Modifications","#fef3c7","#d97706"],["delete","Suppressions","#fee2e2","#ef4444"]].map(([k,l,bg,c])=>(
            <div key={k} onClick={()=>setFilter(filter===k?"all":k)}
              style={{...card,padding:10,textAlign:"center",cursor:"pointer",border:`2px solid ${filter===k?c:"transparent"}`,background:filter===k?bg:"white"}}>
              <div style={{fontWeight:800,fontSize:18,color:c}}>{stats[k]}</div>
              <div style={{fontSize:11,color:"#64748b"}}>{l}</div>
            </div>
          ))}
        </div>

        {/* Filtres */}
        <div style={{...card,marginBottom:12,padding:12}}>
          <div style={{display:"flex",gap:8,flexWrap:"wrap",alignItems:"center"}}>
            <div style={{position:"relative",flex:1,minWidth:160}}>
              <input style={{...input,paddingLeft:30,fontSize:12}} placeholder="Rechercher..."
                value={search} onChange={e=>setSearch(e.target.value)}/>
              <span style={{position:"absolute",left:8,top:"50%",transform:"translateY(-50%)",fontSize:14}}>🔍</span>
            </div>
            <input type="date" style={{...input,width:130,fontSize:11}} value={dateFrom} onChange={e=>setDateFrom(e.target.value)}/>
            <input type="date" style={{...input,width:130,fontSize:11}} value={dateTo} onChange={e=>setDateTo(e.target.value)}/>
            {(search||dateFrom||dateTo||filter!=="all")&&(
              <button onClick={()=>{setSearch("");setDateFrom("");setDateTo("");setFilter("all");}}
                style={{...btn(),background:"#fee2e2",color:"#ef4444",fontSize:11,padding:"5px 10px"}}>✕ Réinitialiser</button>
            )}
          </div>
        </div>

        {/* Liste */}
        <div style={{display:"flex",flexDirection:"column",gap:6}}>
          {activities.length===0&&(
            <div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>
              Aucune activité trouvée.
            </div>
          )}
          {activities.map((a,i)=>{
            const ac = ACTION_COLORS[a.action]||ACTION_COLORS.update;
            const date = fmtDate(a.createdAt);
            return(
              <div key={a.id||i} onClick={()=>setSelected(a)}
                style={{...card,padding:"10px 14px",display:"flex",alignItems:"flex-start",gap:10,cursor:"pointer",transition:"box-shadow 0.15s, transform 0.15s"}}
                onMouseEnter={e=>{e.currentTarget.style.boxShadow="0 4px 16px rgba(0,0,0,0.10)";e.currentTarget.style.transform="translateY(-1px)";}}
                onMouseLeave={e=>{e.currentTarget.style.boxShadow="";e.currentTarget.style.transform="";}}>
                <div style={{flexShrink:0,marginTop:2}}>
                  <span style={{background:ac.bg,color:ac.color,fontSize:10,fontWeight:700,borderRadius:99,padding:"2px 8px",whiteSpace:"nowrap"}}>
                    {ac.icon} {ac.label}
                  </span>
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{fontSize:13,color:"#1e293b",fontWeight:500,marginBottom:2}}>{a.details||"—"}</div>
                  <div style={{display:"flex",gap:10,fontSize:11,color:"#94a3b8",flexWrap:"wrap"}}>
                    <span>👤 {a.userName||"—"}</span>
                    <span>🕐 {date}</span>
                    {a.entity&&<span style={{color:"#7c3aed"}}>{ENTITY_ICONS[a.entity]||"📌"} {ENTITY_LABELS[a.entity]||a.entity}</span>}
                  </div>
                </div>
                <div style={{color:"#cbd5e1",fontSize:16,flexShrink:0}}>›</div>
              </div>
            );
          })}
        </div>

        {activities.length>0&&(
          <div style={{textAlign:"center",fontSize:12,color:"#94a3b8",marginTop:10}}>
            {activities.length} activité(s) · cliquez sur une ligne pour voir les détails
          </div>
        )}
      </div>
    </div>
  );
}

function UsersPage({store, currentUser}){
  const [show,       setShow]       = useState(false);
  const [editing,    setEditing]    = useState(null);
  const [permTab,    setPermTab]    = useState(null);  // user dont on édite les permissions
  const [deletingU,  setDeletingU]  = useState(null);
  const [resetPwU,   setResetPwU]   = useState(null);  // user dont on reset le mdp
  const [newPw,      setNewPw]      = useState("");
  const [pwMsg,      setPwMsg]      = useState("");
  const [form,       setForm]       = useState({name:"",email:"",role:"magasinier",tempPw:""});
  const [showTempPw, setShowTempPw] = useState(false);
  const [permForm,   setPermForm]   = useState({});
  const [showPwReset,setShowPwReset]= useState(false);

  const openAdd = () => {
    setEditing(null);
    setForm({name:"",email:"",role:"magasinier",tempPw:""});
    setShowTempPw(false);
    setShow(true);
  };
  const openEdit = (u) => {
    setEditing(u.id);
    setForm({name:u.name,email:u.email,role:u.role});
    setShow(true);
  };
  const [saving,    setSaving]    = useState(false);
  const [saveError, setSaveError] = useState("");

  const save = async () => {
    if(!form.name.trim()||!form.email.trim()){ setSaveError("⚠️ Nom et email obligatoires."); return; }
    setSaving(true); setSaveError("");
    try {
      if(editing){
        await store.updateUser(editing, form);
      } else {
        await store.addUser(form);
      }
      setShow(false);
      setForm({name:"",email:"",role:"magasinier",tempPw:""});
      setEditing(null);
    } catch(e) {
      setSaveError("❌ " + (e.message||"Erreur inconnue"));
    } finally {
      setSaving(false);
    }
  };

  const openPerms = (u) => {
    const base = DEFAULT_PERMS[u.role] || {};
    setPermForm(u.permissions ? {...base,...u.permissions} : {...base});
    setPermTab(u);
  };
  const savePerms = async () => {
    await store.updateUser(permTab.id, {permissions: permForm});
    setPermTab(null);
  };
  const togglePerm = (sectionId, right) => {
    setPermForm(prev => ({
      ...prev,
      [sectionId]: { ...(prev[sectionId]||{}), [right]: prev[sectionId]?.[right] ? 0 : 1 }
    }));
  };

  const handleResetPassword = async () => {
    if(!newPw || newPw.length < 6) { setPwMsg("⚠️ Minimum 6 caractères."); return; }
    try {
      // Stocker le mot de passe provisoire dans Firestore
      // L'utilisateur devra se reconnecter avec ce mot de passe
      await store.updateUser(resetPwU.id, {
        mustChangePw:  true,
        provisionalPw: newPw,
      });
      // Envoyer aussi un email de réinitialisation en option
      try { await sendPasswordResetEmail(auth, resetPwU.email); } catch(e){}
      setPwMsg("✅ Mot de passe provisoire enregistré : " + newPw + " — Communiquez-le à l'utilisateur.");
      setTimeout(()=>{ setResetPwU(null); setPwMsg(""); setNewPw(""); setShowPwReset(false); }, 5000);
    } catch(e) {
      setPwMsg("❌ Erreur : " + e.message);
    }
  };

  const thS = {padding:"7px 10px",fontSize:11,fontWeight:700,color:"#64748b",background:"#f8fafc",borderBottom:"2px solid #e2e8f0",textAlign:"center"};
  const tdS = {padding:"6px 8px",borderBottom:"1px solid #f1f5f9",textAlign:"center",fontSize:12};

  return(
    <div style={{padding:0}}>
      <ConfirmDelete open={!!deletingU} onClose={()=>setDeletingU(null)}
        label={deletingU?.name||""} onConfirm={async()=>{ await store.deleteUser(deletingU.id); setDeletingU(null); }}/>

      <PageHeader pageId="utilisateurs" title="👥 Utilisateurs" subtitle="Gestion des accès et rôles">
        <button onClick={openAdd} style={{...btn(),background:"white",color:"#4c0519",fontWeight:700}}>+ Nouveau</button>
      </PageHeader>

      <div style={{padding:16}}>
        {/* Modal ajout/modif utilisateur */}
        <Modal open={show} onClose={()=>setShow(false)} title={editing?"✏️ Modifier Utilisateur":"👤 Nouvel Utilisateur"}>
          <div style={{marginBottom:12}}><label style={label}>Nom complet</label><input style={input} value={form.name} onChange={e=>setForm(f=>({...f,name:e.target.value}))}/></div>
          <div style={{marginBottom:12}}><label style={label}>Email</label><input style={{...input,background:editing?"#f8fafc":"white"}} type="email" value={form.email} onChange={e=>setForm(f=>({...f,email:e.target.value}))} disabled={!!editing}/></div>
          <div style={{marginBottom:12}}>
            <label style={label}>Rôle</label>
            <select style={input} value={form.role} onChange={e=>setForm(f=>({...f,role:e.target.value}))}>
              {Object.entries(ROLES).map(([k,v])=><option key={k} value={k}>{v.label}</option>)}
            </select>
          </div>
          {!editing&&(
            <div style={{marginBottom:16}}>
              <label style={label}>Mot de passe provisoire <span style={{color:"#94a3b8",fontWeight:400}}>(optionnel)</span></label>
              <div style={{position:"relative"}}>
                <input
                  style={{...input,paddingRight:38}}
                  type={showTempPw?"text":"password"}
                  value={form.tempPw}
                  onChange={e=>setForm(f=>({...f,tempPw:e.target.value}))}
                  placeholder="Laissez vide pour utiliser PharmaStock2025!"/>
                <button onClick={()=>setShowTempPw(v=>!v)}
                  style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#64748b",fontSize:16,padding:0}}>
                  {showTempPw?"🙈":"👁️"}
                </button>
              </div>
              <div style={{background:"#f0f9ff",borderRadius:8,padding:10,fontSize:11,color:"#0891b2",marginTop:6}}>
                ℹ️ Mot de passe par défaut : <b>PharmaStock2025!</b> — L'utilisateur devra le changer à la première connexion.
              </div>
            </div>
          )}
          {saveError&&<div style={{background:"#fee2e2",color:"#b91c1c",borderRadius:8,padding:"8px 12px",fontSize:12,marginBottom:10}}>{saveError}</div>}
          <button onClick={save} disabled={!form.name||!form.email||saving}
            style={{...btn(),background:(!form.name||!form.email||saving)?"#cbd5e1":"#0891b2",color:"white",width:"100%",padding:11,fontSize:13}}>
            {saving?"⏳ Création en cours...":(editing?"✏️ Enregistrer":"💾 Créer l'utilisateur")}
          </button>
        </Modal>

        {/* Modal permissions granulaires */}
        <Modal open={!!permTab} onClose={()=>setPermTab(null)} title={"🔐 Permissions — " + (permTab?.name||"")}>
          <div style={{fontSize:12,color:"#64748b",marginBottom:12}}>
            Rôle de base : <Badge color={ROLES[permTab?.role]?.color}>{ROLES[permTab?.role]?.label}</Badge>
            <br/><span style={{fontSize:11}}>Ces cases personnalisent les droits par rapport aux droits du rôle.</span>
          </div>
          <div style={{overflowX:"auto"}}>
            <table style={{width:"100%",borderCollapse:"collapse"}}>
              <thead>
                <tr>
                  <th style={{...thS,textAlign:"left"}}>Section</th>
                  <th style={thS}>👁️ Consulter</th>
                  <th style={thS}>✏️ Modifier</th>
                  <th style={thS}>🗑️ Supprimer</th>
                </tr>
              </thead>
              <tbody>
                {SECTIONS.map(s => (
                  <tr key={s.id}>
                    <td style={{...tdS,textAlign:"left",fontWeight:500,color:"#1e293b"}}>{s.label}</td>
                    {["r","w","d"].map(right=>(
                      <td key={right} style={tdS}>
                        <input type="checkbox"
                          checked={!!(permForm[s.id]?.[right])}
                          onChange={()=>togglePerm(s.id,right)}
                          style={{width:16,height:16,cursor:"pointer",accentColor:"#0891b2"}}/>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
          <button onClick={savePerms} style={{...btn(),background:"#0891b2",color:"white",width:"100%",padding:11,marginTop:16}}>
            💾 Enregistrer les permissions
          </button>
        </Modal>

        {/* Modal réinitialisation mot de passe */}
        <Modal open={!!resetPwU} onClose={()=>{setResetPwU(null);setPwMsg("");setNewPw("");}} title={"🔑 Mot de passe — " + (resetPwU?.name||"")}>
          {pwMsg ? (
            <Alert type={pwMsg.startsWith("✅")?"success":pwMsg.startsWith("⚠️")?"warn":"error"}>{pwMsg}</Alert>
          ) : (
            <>
              <div style={{fontSize:13,color:"#64748b",marginBottom:12}}>
                Définir un mot de passe provisoire pour <b>{resetPwU?.name}</b> ({resetPwU?.email})
              </div>
              <div style={{marginBottom:12}}>
                <label style={label}>Nouveau mot de passe provisoire</label>
                <div style={{position:"relative"}}>
                  <input
                    style={{...input,paddingRight:38}}
                    type={showPwReset?"text":"password"}
                    value={newPw}
                    onChange={e=>setNewPw(e.target.value)}
                    placeholder="Minimum 6 caractères"/>
                  <button onClick={()=>setShowPwReset(v=>!v)}
                    style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#64748b",fontSize:16,padding:0}}>
                    {showPwReset?"🙈":"👁️"}
                  </button>
                </div>
              </div>
              <div style={{display:"flex",gap:8}}>
                <button onClick={handleResetPassword}
                  style={{...btn(),background:"#0891b2",color:"white",flex:1,padding:11,fontSize:13}}>
                  💾 Définir ce mot de passe
                </button>
                <button onClick={()=>{ store.updateUser(resetPwU.id,{mustChangePw:true}); sendPasswordResetEmail(auth,resetPwU.email).then(()=>setPwMsg("✅ Email envoyé à "+resetPwU.email)).catch(e=>setPwMsg("❌ "+e.message)); }}
                  style={{...btn(),background:"#f59e0b",color:"white",flex:1,padding:11,fontSize:13}}>
                  📧 Envoyer email reset
                </button>
              </div>
            </>
          )}
        </Modal>

        {/* Liste utilisateurs */}
        <div style={{display:"flex",flexDirection:"column",gap:8}}>
          {store.users.map(u=>{
            const isSuperuser    = u.isSuperuser || u.role==="superuser";
            const isTargetAdmin  = u.role==="admin";
            const isCurrentUser  = u.id===currentUser?.uid;
            const amISuperuser   = currentUser?.isSuperuser || currentUser?.role==="superuser";
            const amIAdmin       = currentUser?.role==="admin";

            // Règles de protection :
            // - Superuser → intouchable par tout le monde
            // - Admin cible → seul le superuser peut le modifier/supprimer/démettre
            // - Soi-même → ne peut pas se supprimer ni se démettre
            const isProtected    = isSuperuser || (isTargetAdmin && !amISuperuser);
            const canEdit        = !isSuperuser && (!isTargetAdmin || amISuperuser) && !isCurrentUser;
            const canEditPerms   = !isSuperuser && (!isTargetAdmin || amISuperuser);
            const canResetPw     = !isSuperuser && (!isTargetAdmin || amISuperuser);
            const canDelete      = !isSuperuser && !isCurrentUser && (!isTargetAdmin || amISuperuser);
            const canToggleAdmin = !isSuperuser && !isCurrentUser && amISuperuser; // seul superuser peut promouvoir/rétrograder admin

            return(
            <div key={u.id} style={{...card,padding:14,border:isSuperuser?"2px solid #f59e0b":isTargetAdmin?"2px solid #7c3aed":"1.5px solid #f1f5f9"}}>
              <div style={{display:"flex",alignItems:"center",gap:12}}>
                <div style={{width:40,height:40,borderRadius:"50%",background:(ROLES[u.role]?.color||"#94a3b8")+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:20,flexShrink:0}}>
                  {isSuperuser?"⭐":isTargetAdmin?"🛡️":"👤"}
                </div>
                <div style={{flex:1,minWidth:0}}>
                  <div style={{display:"flex",alignItems:"center",gap:6}}>
                    <div style={{fontWeight:700,color:"#1e293b",fontSize:13}}>{u.name}</div>
                    {isSuperuser&&<span style={{background:"#f59e0b",color:"white",fontSize:9,fontWeight:700,borderRadius:99,padding:"1px 6px"}}>SUPER</span>}
                    {isTargetAdmin&&!isSuperuser&&<span style={{background:"#7c3aed",color:"white",fontSize:9,fontWeight:700,borderRadius:99,padding:"1px 6px"}}>ADMIN</span>}
                  </div>
                  <div style={{fontSize:11,color:"#64748b"}}>{u.email}</div>
                  <Badge color={ROLES[u.role]?.color||"#94a3b8"}>{ROLES[u.role]?.label||u.role}</Badge>
                  {u.permissions&&<span style={{fontSize:10,color:"#7c3aed",marginLeft:6}}>🔐 Perms perso.</span>}
                  {u.mustChangePw&&<span style={{fontSize:10,color:"#f59e0b",marginLeft:6}}>⚠️ Doit changer mdp</span>}
                </div>
                <div style={{display:"flex",gap:5,flexWrap:"wrap",justifyContent:"flex-end"}}>
                  {canEdit      &&<button onClick={()=>openEdit(u)}    style={{...btn(),background:"#f0f9ff",color:"#0891b2",padding:"5px 8px",fontSize:11}} title="Modifier">✏️</button>}
                  {canEditPerms &&<button onClick={()=>openPerms(u)}   style={{...btn(),background:"#fdf4ff",color:"#7c3aed",padding:"5px 8px",fontSize:11}} title="Permissions">🔐</button>}
                  {canResetPw   &&<button onClick={()=>setResetPwU(u)} style={{...btn(),background:"#fffbeb",color:"#d97706",padding:"5px 8px",fontSize:11}} title="Mot de passe provisoire">🔑</button>}
                  {canToggleAdmin&&(
                    <button onClick={()=>store.updateUser(u.id,{role:u.role==="admin"?"magasinier":"admin"})}
                      style={{...btn(),background:u.role==="admin"?"#ede9fe":"#f8fafc",color:u.role==="admin"?"#7c3aed":"#64748b",padding:"5px 8px",fontSize:11}}
                      title={u.role==="admin"?"Retirer admin":"Promouvoir admin"}>
                      {u.role==="admin"?"🛡️ -Admin":"🛡️ Admin"}
                    </button>
                  )}
                  {canDelete    &&<button onClick={()=>setDeletingU(u)} style={{...btn(),background:"#fee2e2",color:"#ef4444",padding:"5px 8px",fontSize:11}} title="Supprimer">🗑️</button>}
                  {isProtected  &&!isCurrentUser&&<span style={{fontSize:10,color:isSuperuser?"#f59e0b":"#7c3aed",padding:"5px 4px"}}>🔒</span>}
                </div>
              </div>
            </div>
            );
          })}
          {store.users.length===0&&<div style={{...card,textAlign:"center",padding:40,color:"#94a3b8"}}>Aucun utilisateur.</div>}
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// LOGIN — Firebase Auth
// ─────────────────────────────────────────────
function LoginPage({onLogin}){
  const [email,   setEmail]   = useState("");
  const [password,setPassword]= useState("");
  const [err,     setErr]     = useState("");
  const [loading, setLoading] = useState(false);
  const [showPw,  setShowPw]  = useState(false);

  const tryLogin = async () => {
    if (!email || !password) { setErr("Veuillez saisir votre email et mot de passe."); return; }
    setLoading(true); setErr("");
    try {
      const cred = await signInWithEmailAndPassword(auth, email, password);
      // Charger le profil Firestore
      const snap = await getDoc(doc(db, "users", cred.user.uid));
      let profile;
      if (snap.exists()) {
        profile = { uid: cred.user.uid, ...snap.data() };
      } else {
        // Premier utilisateur : créer profil admin automatiquement
        profile = {
          uid:   cred.user.uid,
          name:  cred.user.displayName || email.split("@")[0],
          email: cred.user.email,
          role:  "admin",
        };
        await setDoc(doc(db, "users", cred.user.uid), {
          ...profile, createdAt: serverTimestamp(),
        });
      }
      onLogin(profile);
    } catch(e) {
      const msgs = {
        "auth/wrong-password":    "Mot de passe incorrect.",
        "auth/user-not-found":    "Aucun compte avec cet email.",
        "auth/invalid-email":     "Format d'email invalide.",
        "auth/invalid-credential":"Email ou mot de passe incorrect.",
        "auth/too-many-requests": "Trop de tentatives. Réessayez plus tard.",
      };
      setErr(msgs[e.code] || "Erreur : " + e.message);
    } finally { setLoading(false); }
  };

  return(
    <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#0f172a,#1e3a5f)",display:"flex",alignItems:"center",justifyContent:"center",padding:16}}>
      <div style={{background:"white",borderRadius:20,padding:32,width:"100%",maxWidth:420,boxShadow:"0 20px 60px rgba(0,0,0,0.3)"}}>
        {/* Logo complet CHNCAK */}
        <div style={{textAlign:"center",marginBottom:24}}>
          <img src={LOGO_CHNCAK_B64} alt="CHNCAK PharmaStock"
            style={{width:"100%",maxWidth:360,height:"auto",borderRadius:14,marginBottom:16,boxShadow:"0 4px 20px rgba(8,145,178,0.25)"}}/>
          <div style={{fontSize:13,color:"#64748b",marginTop:4}}>Gestion des Inventaires Pharmaceutiques</div>
        </div>
        {err&&<Alert type="error">❌ {err}</Alert>}
        <div style={{marginBottom:14}}>
          <label style={label}>Email</label>
          <input style={input} type="email" value={email}
            onChange={e=>setEmail(e.target.value)}
            placeholder="votre@email.com"
            onKeyDown={e=>e.key==="Enter"&&tryLogin()}/>
        </div>
        <div style={{marginBottom:20}}>
          <label style={label}>Mot de passe</label>
          <div style={{position:"relative"}}>
            <input style={{...input,paddingRight:38}} type={showPw?"text":"password"} value={password}
              onChange={e=>setPassword(e.target.value)}
              placeholder="••••••••"
              onKeyDown={e=>e.key==="Enter"&&tryLogin()}/>
            <button onClick={()=>setShowPw(v=>!v)}
              style={{position:"absolute",right:8,top:"50%",transform:"translateY(-50%)",background:"none",border:"none",cursor:"pointer",color:"#64748b",fontSize:16,padding:0,lineHeight:1}}>
              {showPw?"🙈":"👁️"}
            </button>
          </div>
        </div>
        <button onClick={tryLogin} disabled={loading}
          style={{...btn(),width:"100%",padding:13,background:loading?"#cbd5e1":"linear-gradient(135deg,#0891b2,#0e7490)",color:"white",fontSize:15}}>
          {loading?"⏳ Connexion en cours...":"Se Connecter"}
        </button>
        <div style={{marginTop:16,fontSize:11,color:"#94a3b8",textAlign:"center"}}>
          🔒 Authentification sécurisée
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────
// MAIN APP — avec Firebase Auth persistante
// ─────────────────────────────────────────────
export default function App(){
  const [user,            setUser]            = useState(null);
  const [authLoading,     setAuthLoading]     = useState(true);
  const [page,            setPage]            = useState("dashboard");
  const [menuOpen,        setMenuOpen]        = useState(false);
  const [aiOpen,          setAiOpen]          = useState(false);
  const [supplierModal,   setSupplierModal]   = useState(false);
  const [activeSupplier,  setActiveSupplierState] = useState(()=>{
    // Restauration immédiate depuis localStorage au chargement
    try {
      const saved = localStorage.getItem("pharma_active_supplier");
      return saved ? JSON.parse(saved) : null;
    } catch(e) { return null; }
  });
  const [pendingInvoiceId,setPendingInvoiceId] = useState(null);
  const [profileOpen,setProfileOpen] = useState(false);
  const [profilePw,setProfilePw]     = useState({current:"",next:"",confirm:""});
  const [profileMsg,setProfileMsg]   = useState("");

  const handleUpdatePassword = async () => {
    if(profilePw.next.length<6){setProfileMsg("❌ Minimum 6 caractères.");return;}
    if(profilePw.next!==profilePw.confirm){setProfileMsg("❌ Les mots de passe ne correspondent pas.");return;}
    try{
      await updatePassword(auth.currentUser, profilePw.next);
      setProfileMsg("✅ Mot de passe modifié avec succès !");
      setProfilePw({current:"",next:"",confirm:""});
      setTimeout(()=>{setProfileOpen(false);setProfileMsg("");},2000);
    }catch(e){
      if(e.code==="auth/requires-recent-login") setProfileMsg("❌ Session expirée. Reconnectez-vous.");
      else setProfileMsg("❌ Erreur : "+e.message);
    }
  }; // facture à pré-remplir en messagerie

  // ── Firebase Auth : détecte session existante au chargement ──
  useEffect(()=>{
    const unsub = onAuthStateChanged(auth, async fbUser => {
      if (fbUser) {
        try {
          const snap = await getDoc(doc(db,"users",fbUser.uid));
          if (snap.exists()) {
            setUser({ uid: fbUser.uid, ...snap.data() });
          } else {
            // Profil manquant → créer automatiquement en admin
            const profile = {
              name:  fbUser.displayName || fbUser.email.split("@")[0],
              email: fbUser.email,
              role:  "admin",
            };
            await setDoc(doc(db,"users",fbUser.uid), { ...profile, createdAt: serverTimestamp() });
            setUser({ uid: fbUser.uid, ...profile });
          }
        } catch(e) {
          console.error("Erreur chargement profil:", e);
          setUser(null);
        }
      } else {
        setUser(null);
      }
      setAuthLoading(false);
    });
    return unsub;
  },[]);

  const store = useStore(user?.uid, user?.name || user?.email || "Inconnu");
  const ai    = useAI();

  // ── Synchroniser activeSupplier avec les données fraîches de Firestore ──
  // (au cas où le nom/email du fournisseur aurait changé)
  useEffect(()=>{
    if(!activeSupplier || store.suppliers.length === 0) return;
    const fresh = store.suppliers.find(s => s.id === activeSupplier.id);
    if(fresh && (fresh.name !== activeSupplier.name || fresh.email !== activeSupplier.email)){
      setActiveSupplierState(fresh);
      localStorage.setItem("pharma_active_supplier", JSON.stringify(fresh));
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  },[store.suppliers]);

  const setActiveSupplier = async (s) => {
    setActiveSupplierState(s);
    // Sauvegarder dans localStorage pour restauration immédiate
    if(s) localStorage.setItem("pharma_active_supplier", JSON.stringify(s));
    else localStorage.removeItem("pharma_active_supplier");
    setSupplierModal(false); setMenuOpen(false);
    // Persister aussi dans Firestore
    if(user?.uid) {
      try {
        await updateDoc(doc(db,"users",user.uid), { activeSupplier: s?.id || null });
      } catch(e) { console.warn("Erreur sauvegarde fournisseur:", e); }
    }
  };

  const nav = (p, extra={}) => {
    setPage(p);
    setMenuOpen(false);
    setAiOpen(false);
    if(extra.invoiceId !== undefined) setPendingInvoiceId(extra.invoiceId);
  };
  const logout = async () => {
    await signOut(auth);
    setUser(null);
    // Ne pas effacer le fournisseur actif — sera restauré à la prochaine connexion
    setPage("dashboard");
  };

  // ── Écran de chargement pendant vérification Auth ──
  if(authLoading) return (
    <div style={{minHeight:"100vh",background:"linear-gradient(135deg,#0f172a,#1e3a5f)",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:20}}>
      <img src={LOGO_B64} alt="CHNCAK" style={{width:90,height:90,borderRadius:"50%",objectFit:"cover",border:"3px solid #38bdf8"}}/>
      <div style={{color:"#38bdf8",fontWeight:700,fontSize:16}}>CHNCAK PharmaStock</div>
      <div style={{color:"#64748b",fontSize:13}}>⏳ Chargement en cours...</div>
    </div>
  );

  if(!user) return <LoginPage onLogin={setUser}/>;

  // ── Écran de chargement des données Firestore ──
  if(store.loading) return (
    <div style={{minHeight:"100vh",background:"#f8fafc",display:"flex",flexDirection:"column",alignItems:"center",justifyContent:"center",gap:16}}>
      <img src={LOGO_B64} alt="CHNCAK" style={{width:70,height:70,borderRadius:"50%",objectFit:"cover",border:"3px solid #0891b2"}}/>
      <div style={{color:"#0891b2",fontWeight:700}}>Synchronisation des données...</div>
      <div style={{color:"#94a3b8",fontSize:12}}>Connexion en cours...</div>
    </div>
  );

  const unread=store.messages.filter(m=>!m.read).length;
  const role=user.role||"magasinier";
  const activeDepot=activeSupplier ? store.depots.find(d=>d.supplierId===activeSupplier.id) : null;

  const renderPage=()=>{
    const props={store,activeSupplier,activeDepot,onNav:nav,currentUser:user};
    switch(page){
      case "dashboard":    return <Dashboard {...props}/>;
      case "entrees":      return <DocumentForm type="entry"  {...props} ai={ai}/>;
      case "retours":      return <DocumentForm type="return" {...props} ai={ai}/>;
      case "inventaire":   return <InventoryPage store={store} activeSupplier={activeSupplier} currentUser={user}/>;
      case "factures":     return <InvoicesPage store={store} activeSupplier={activeSupplier} onNav={nav} currentUser={user}/>;
      case "hist-inv":
        return <InventoryHistoryPage store={store} activeSupplier={activeSupplier} user={user}/>;
      case "hist-fact": {
        const factItems=store.invoices.filter(i=>!activeSupplier||i.supplierId===activeSupplier?.id);
        const exportFactCSV=()=>{
          const rows=factItems.flatMap(inv=>(inv.items||[]).map(it=>[inv.reference,inv.month,inv.supplier,it.productName,it.qty,Number(it.unitPrice||0),Number(it.total||0),Number(inv.total||0)]));
          downloadExcel("historique_factures_"+Date.now()+".xlsx",rows,["Référence","Période","Fournisseur","Produit","Qté","Prix unit. FCFA","Total ligne FCFA","Total facture FCFA"]);
        };
        return <HistoryPage title="Historique Situations" icon="📁" pageId="hist-fact" items={factItems} empty="Aucune facture." onExportCSV={exportFactCSV}
          renderItem={inv=>(
            <div key={inv.id} style={{...card,display:"flex",justifyContent:"space-between",flexWrap:"wrap",gap:8,alignItems:"center"}}>
              <div>
                <div style={{fontWeight:700,color:"#1e293b",fontSize:13}}>{inv.reference}</div>
                <div style={{fontSize:11,color:"#64748b"}}>{inv.supplier} · {inv.month}</div>
                {inv.createdByName&&<div style={{fontSize:10,color:"#94a3b8"}}>👤 {inv.createdByName}</div>}
              </div>
              <div style={{display:"flex",alignItems:"center",gap:6,flexWrap:"wrap"}}>
                <div style={{fontWeight:800,color:"#0891b2",fontSize:14}}>{Number(inv.total||0).toLocaleString("fr-FR")} FCFA</div>
                {/* CSV */}
                <button onClick={e=>{e.stopPropagation();downloadInvoiceCSV(inv);}} style={{background:"#f0fdf4",color:"#059669",border:"1px solid #bbf7d0",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:600}}>⬇️ CSV</button>
                {/* PDF */}
                <button onClick={e=>{
                  e.stopPropagation();
                  const tbl=""+pdfHeader("FACTURE",inv.reference)+
                    "<div style=\"display:grid;grid-template-columns:1fr 1fr;gap:10px;margin-bottom:14px;\">"+
                    "<div style=\"background:#f8fafc;padding:8px 10px;border-radius:6px;\"><div style=\"font-size:9px;font-weight:700;color:#64748b;text-transform:uppercase;\">Fournisseur</div><div style=\"font-weight:600;\">"+inv.supplier+"</div></div>"+
                    "<div style=\"background:#f8fafc;padding:8px 10px;border-radius:6px;\"><div style=\"font-size:9px;font-weight:700;color:#64748b;text-transform:uppercase;\">Période</div><div style=\"font-weight:600;\">"+inv.month+"</div></div></div>"+
                    "<table><tr><th>Produit</th><th>Qté</th><th>Prix unit.</th><th>Total</th></tr>"+
                    (inv.items||[]).map(it=>"<tr><td>"+it.productName+"</td><td>"+it.qty+"</td><td>"+Number(it.unitPrice||0).toLocaleString("fr-FR")+" FCFA</td><td>"+Number(it.total||0).toLocaleString("fr-FR")+" FCFA</td></tr>").join("")+
                    "<tr class=\"total-row\"><td colspan=3>TOTAL</td><td>"+Number(inv.total||0).toLocaleString("fr-FR")+" FCFA</td></tr></table>"+
                    "<div class=\"footer\">Généré le "+new Date().toLocaleDateString("fr-FR")+"</div>";
                  downloadPDF("facture_"+inv.reference,tbl);
                }} style={{background:"#fef3c7",color:"#92400e",border:"1px solid #fcd34d",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:600}}>⬇️ PDF</button>
                {/* Mail */}
                <button onClick={e=>{
                  e.stopPropagation();
                  const details=(inv.items||[]).map(it=>`- ${it.productName} | Qté: ${it.qty} | Total: ${Number(it.total||0).toLocaleString("fr-FR")} FCFA`).join("\n");
                  openMailClient({
                    to: activeSupplier?.email || "",
                    subject: `Facture ${inv.reference} — ${inv.month}`,
                    body:
                      `Bonjour,\n\n`+
                      `Veuillez trouver ci-joint la facture ${inv.reference} pour la période ${inv.month}.\n\n`+
                      `Fournisseur : ${inv.supplier}\n`+
                      `Période     : ${inv.month}\n\n`+
                      `Détails :\n${details}\n\n`+
                      `TOTAL : ${Number(inv.total||0).toLocaleString("fr-FR")} FCFA\n\n`+
                      `Cordialement,\nCHNCAK PharmaStock`
                  });
                }} style={{background:"#0891b2",color:"white",border:"none",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:600}}>📧 Mail</button>
                {can(user,"hist-fact","d")&&<button onClick={e=>{e.stopPropagation();store.deleteInvoice(inv.id);}} style={{background:"#fee2e2",color:"#ef4444",border:"none",borderRadius:6,padding:"3px 8px",cursor:"pointer",fontSize:11,fontWeight:600}}>🗑️</button>}
              </div>
            </div>
          )}/>;
      }
      case "messagerie":   return <MessagingPage store={store} activeSupplier={activeSupplier} pendingInvoiceId={pendingInvoiceId} onClearPending={()=>setPendingInvoiceId(null)} currentUser={user}/>;
      case "produits":     return <ProductsPage store={store} activeSupplier={activeSupplier} currentUser={user}/>;
      case "services":        return can(user,"services","r")?<ServicesPage store={store} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès non autorisé.</Alert></div>;
      case "transferts":      return can(user,"transferts","r")?<TransfertsPage store={store} activeSupplier={activeSupplier} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès non autorisé.</Alert></div>;
      case "consommations":   return can(user,"consommations","r")?<ConsommationsPage store={store} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès non autorisé.</Alert></div>;
      case "retours-service": return can(user,"retours-service","r")?<RetoursServicePage store={store} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès non autorisé.</Alert></div>;
      case "receptions":      return can(user,"receptions","r")?<ReceptionsPage store={store} activeSupplier={activeSupplier} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès non autorisé.</Alert></div>;
      case "stock-service":   return can(user,"stock-service","r")?<StockServicePage store={store} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès non autorisé.</Alert></div>;
      case "statistiques":    return can(user,"statistiques","r")?<StatistiquesPage store={store} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès non autorisé.</Alert></div>;
      case "depots":       return <DepotsPage store={store} activeSupplier={activeSupplier} currentUser={user}/>;

      case "fournisseurs": return <FournisseursPage store={store} activeSupplier={activeSupplier} onActivate={setActiveSupplier} currentUser={user}/>;
      case "activites":    return can(user,"activites","r")?<ActivitiesPage store={store} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès non autorisé. Contactez l'administrateur.</Alert></div>;
      case "utilisateurs": return role==="admin"?<UsersPage store={store} currentUser={user}/>:<div style={{padding:24}}><Alert type="error">Accès refusé.</Alert></div>;
      default:             return <Dashboard store={store} activeSupplier={activeSupplier} activeDepot={activeDepot}/>;
    }
  };

  return(
    <div style={{display:"flex",flexDirection:"column",height:"100vh",background:"#f8fafc",fontFamily:"-apple-system,BlinkMacSystemFont,'Segoe UI',sans-serif",overflow:"hidden"}}>
      <TopBar page={page} activeSupplier={activeSupplier} onMenu={()=>setMenuOpen(true)}
        onAI={()=>{
          if(!can(user,"assistant_ia","r")){ alert("⛔ Accès à l'Assistant IA non autorisé. Contactez l'administrateur."); return; }
          setAiOpen(v=>!v);setMenuOpen(false);
        }} aiOpen={aiOpen} currentUser={user}
        unread={unread} onLogout={logout} onChangeSupplier={()=>setSupplierModal(true)} onNav={nav}
        onProfile={()=>setProfileOpen(true)} userName={user?.name||user?.email}/>
      <div id="main-scroll-area" style={{flex:1,overflowY:"auto"}}>
        {renderPage()}
      </div>
      <Sidebar open={menuOpen} onClose={()=>setMenuOpen(false)} page={page} onNav={nav}
        user={user} unread={unread} activeSupplier={activeSupplier}
        onChangeSupplier={()=>{setSupplierModal(true);setMenuOpen(false);}}/>
      <AIPanel open={aiOpen} onClose={()=>setAiOpen(false)} ai={ai} onNav={nav}
        store={store} page={page} activeSupplier={activeSupplier} currentUser={user}/>
      {/* Modal Mon Profil */}
      <Modal open={profileOpen} onClose={()=>{setProfileOpen(false);setProfileMsg("");setProfilePw({current:"",next:"",confirm:""});}} title="👤 Mon Profil">
        <div style={{marginBottom:16}}>
          <div style={{display:"flex",alignItems:"center",gap:12,padding:"12px 0",borderBottom:"1px solid #f1f5f9",marginBottom:14}}>
            <div style={{width:50,height:50,borderRadius:"50%",background:ROLES[user?.role]?.color+"22",display:"flex",alignItems:"center",justifyContent:"center",fontSize:24}}>👤</div>
            <div>
              <div style={{fontWeight:700,color:"#1e293b",fontSize:15}}>{user?.name}</div>
              <div style={{fontSize:12,color:"#64748b"}}>{user?.email}</div>
              <Badge color={ROLES[user?.role]?.color}>{ROLES[user?.role]?.label}</Badge>
            </div>
          </div>
          <div style={{fontWeight:700,color:"#374151",fontSize:13,marginBottom:12}}>🔑 Changer mon mot de passe</div>
          {profileMsg&&<Alert type={profileMsg.startsWith("✅")?"success":"error"}>{profileMsg}</Alert>}
          <div style={{marginBottom:10}}><label style={label}>Nouveau mot de passe</label>
            <input style={input} type="password" value={profilePw.next}
              onChange={e=>setProfilePw(p=>({...p,next:e.target.value}))} placeholder="Minimum 6 caractères"/>
          </div>
          <div style={{marginBottom:16}}><label style={label}>Confirmer</label>
            <input style={input} type="password" value={profilePw.confirm}
              onChange={e=>setProfilePw(p=>({...p,confirm:e.target.value}))} placeholder="Répéter le mot de passe"/>
          </div>
          <button onClick={handleUpdatePassword}
            disabled={!profilePw.next||!profilePw.confirm}
            style={{...btn(),background:"#0891b2",color:"white",width:"100%",padding:11,fontSize:14}}>
            🔑 Mettre à jour le mot de passe
          </button>
        </div>
      </Modal>

      <SupplierSelector open={supplierModal} suppliers={store.suppliers} current={activeSupplier}
        onSelect={setActiveSupplier} onClose={()=>setSupplierModal(false)}/>
    </div>
  );
}